    def _weighted_unit_rank(self, values: np.ndarray,
                            weights: np.ndarray) -> np.ndarray:
        vals = np.asarray(values, dtype=np.float64)
        w = np.asarray(weights, dtype=np.float64)
        if vals.size == 0:
            return np.asarray([], dtype=np.float64)
        finite = np.isfinite(vals) & np.isfinite(w) & (w > 0.0)
        if not np.all(finite):
            vals = np.where(finite, vals, 0.0)
            w = np.where(finite, w, 1.0)
        order = np.argsort(vals)
        ranks = np.zeros(vals.size, dtype=np.float64)
        cumulative = np.cumsum(w[order])
        denom = max(float(cumulative[-1]), 1.0e-12)
        ranks[order] = (cumulative - 0.5 * w[order]) / denom
        return np.clip(ranks, 0.0, 1.0)

    def _weighted_percentile_local(self, values: np.ndarray,
                                   weights: np.ndarray,
                                   percentile: float) -> float:
        vals = np.asarray(values, dtype=np.float64)
        w = np.asarray(weights, dtype=np.float64)
        finite = np.isfinite(vals) & np.isfinite(w) & (w > 0.0)
        if not np.any(finite):
            return 0.0
        vals = vals[finite]
        w = w[finite]
        order = np.argsort(vals)
        vals = vals[order]
        w = w[order]
        cumulative = np.cumsum(w)
        cutoff = float(np.clip(percentile, 0.0, 100.0)) / 100.0 * float(cumulative[-1])
        idx = int(np.searchsorted(cumulative, cutoff, side="left"))
        return float(vals[np.clip(idx, 0, vals.size - 1)])

    def _set_p109_hypsometry_globals(self, world, grid, before, after,
                                     sea_level, land_mask) -> None:
        area = np.asarray(grid.cell_area, dtype=np.float64)
        land = np.asarray(land_mask, dtype=bool)
        if not land.any():
            for key in (
                "terrain.last_p109_land_mean_before_m",
                "terrain.last_p109_land_mean_after_m",
                "terrain.last_p109_land_p50_before_m",
                "terrain.last_p109_land_p50_after_m",
                "terrain.last_p109_land_p90_before_m",
                "terrain.last_p109_land_p90_after_m",
            ):
                world.set_g(key, 0.0)
            world.set_g("terrain.last_p109_land_mask_preserved", 1.0)
            return
        rel_before = np.asarray(before, dtype=np.float64) - float(sea_level)
        rel_after = np.asarray(after, dtype=np.float64) - float(sea_level)
        weights = area[land]
        world.set_g(
            "terrain.last_p109_land_mean_before_m",
            float(np.average(rel_before[land], weights=weights)),
        )
        world.set_g(
            "terrain.last_p109_land_mean_after_m",
            float(np.average(rel_after[land], weights=weights)),
        )
        world.set_g(
            "terrain.last_p109_land_p50_before_m",
            self._weighted_percentile_local(rel_before[land], weights, 50.0),
        )
        world.set_g(
            "terrain.last_p109_land_p50_after_m",
            self._weighted_percentile_local(rel_after[land], weights, 50.0),
        )
        world.set_g(
            "terrain.last_p109_land_p90_before_m",
            self._weighted_percentile_local(rel_before[land], weights, 90.0),
        )
        world.set_g(
            "terrain.last_p109_land_p90_after_m",
            self._weighted_percentile_local(rel_after[land], weights, 90.0),
        )
        world.set_g(
            "terrain.last_p109_land_mask_preserved",
            1.0 if np.array_equal(land, np.asarray(after) >= float(sea_level)) else 0.0,
        )

    def _shortest_path_within_mask(self, grid, start, target, allowed,
                                   max_steps: int | None = None) -> np.ndarray:
        start = int(start)
        target = int(target)
        allowed = np.asarray(allowed, dtype=bool)
        if (
            start < 0 or start >= grid.n
            or target < 0 or target >= grid.n
            or not allowed[start]
            or not allowed[target]
        ):
            return np.asarray([], dtype=np.int64)
        if start == target:
            return np.asarray([start], dtype=np.int64)
        prev = np.full(grid.n, -1, dtype=np.int64)
        seen = np.zeros(grid.n, dtype=bool)
        queue = [start]
        seen[start] = True
        head = 0
        depth = np.zeros(grid.n, dtype=np.int16)
        while head < len(queue):
            c = queue[head]
            head += 1
            if max_steps is not None and int(depth[c]) >= int(max_steps):
                continue
            for nb in grid.neighbors[c]:
                nb = int(nb)
                if seen[nb] or not allowed[nb]:
                    continue
                prev[nb] = c
                if nb == target:
                    path = [target]
                    cur = c
                    while cur >= 0:
                        path.append(int(cur))
                        if cur == start:
                            break
                        cur = int(prev[cur])
                    path.reverse()
                    return np.asarray(path, dtype=np.int64)
                seen[nb] = True
                depth[nb] = depth[c] + 1
                queue.append(nb)
        return np.asarray([], dtype=np.int64)

    def _ranked_shortest_path_within_mask(
        self,
        grid,
        start,
        target,
        allowed,
        rank,
        max_steps: int | None = None,
    ) -> np.ndarray:
        """Shortest graph path with deterministic rank/directness tie-breaking."""
        start = int(start)
        target = int(target)
        allowed = np.asarray(allowed, dtype=bool)
        if (
            start < 0 or start >= grid.n
            or target < 0 or target >= grid.n
            or not allowed[start]
            or not allowed[target]
        ):
            return np.asarray([], dtype=np.int64)
        if start == target:
            return np.asarray([start], dtype=np.int64)

        rank_arr = np.asarray(rank, dtype=np.float64)
        if rank_arr.shape != (grid.n,):
            rank_arr = np.zeros(grid.n, dtype=np.float64)
        finite = np.isfinite(rank_arr) & allowed
        rank_norm = np.zeros(grid.n, dtype=np.float64)
        if finite.any():
            vals = rank_arr[finite]
            lo = float(np.min(vals))
            hi = float(np.max(vals))
            if hi > lo:
                rank_norm[finite] = (rank_arr[finite] - lo) / (hi - lo)

        start_vec = np.asarray(grid.xyz[start], dtype=np.float64)
        target_vec = np.asarray(grid.xyz[target], dtype=np.float64)
        dot = float(np.clip(start_vec @ target_vec, -1.0, 1.0))
        arc = max(float(np.arccos(dot)), 1.0e-9)
        normal = np.cross(start_vec, target_vec)
        normal_norm = float(np.linalg.norm(normal))
        direct_penalty = np.zeros(grid.n, dtype=np.float64)
        if normal_norm > 1.0e-12:
            normal = normal / normal_norm
            cross_track = np.abs(np.arcsin(
                np.clip(grid.xyz @ normal, -1.0, 1.0)
            ))
            direct_penalty = np.clip(cross_track / arc, 0.0, 2.0)

        best = np.full(grid.n, np.inf, dtype=np.float64)
        hops = np.full(grid.n, -1, dtype=np.int16)
        prev = np.full(grid.n, -1, dtype=np.int64)
        best[start] = 0.0
        hops[start] = 0
        heap: list[tuple[float, int, int]] = [(0.0, 0, start)]
        while heap:
            dist, hop, c = heapq.heappop(heap)
            if dist > best[c] + 1.0e-12 or hop != int(hops[c]):
                continue
            if c == target:
                path = [target]
                cur = target
                while cur != start and cur >= 0:
                    cur = int(prev[cur])
                    path.append(cur)
                path.reverse()
                return np.asarray(path, dtype=np.int64)
            if max_steps is not None and hop >= int(max_steps):
                continue
            for nb0 in grid.neighbors[c]:
                nb = int(nb0)
                if not allowed[nb]:
                    continue
                step = (
                    1.0
                    - 0.30 * float(rank_norm[nb])
                    + 0.16 * float(direct_penalty[nb])
                )
                step = max(step, 0.45)
                nd = dist + step
                nh = hop + 1
                if max_steps is not None and nh > int(max_steps):
                    continue
                if nd + 1.0e-12 < best[nb]:
                    best[nb] = nd
                    hops[nb] = nh
                    prev[nb] = c
                    heapq.heappush(heap, (nd, nh, nb))
        return np.asarray([], dtype=np.int64)

    def _path_directness_penalty(self, grid, path: np.ndarray) -> float:
        path = np.asarray(path, dtype=np.int64)
        if path.size <= 2:
            return 0.0
        start_vec = np.asarray(grid.xyz[int(path[0])], dtype=np.float64)
        end_vec = np.asarray(grid.xyz[int(path[-1])], dtype=np.float64)
        dot = float(np.clip(start_vec @ end_vec, -1.0, 1.0))
        arc = max(float(np.arccos(dot)), 1.0e-9)
        normal = np.cross(start_vec, end_vec)
        normal_norm = float(np.linalg.norm(normal))
        if normal_norm <= 1.0e-12:
            return 0.0
        normal = normal / normal_norm
        cross_track = np.abs(np.arcsin(
            np.clip(grid.xyz[path] @ normal, -1.0, 1.0)
        ))
        return float(np.mean(cross_track) / arc)

    def _ranked_orogenic_path_guard(
        self,
        grid,
        base_path: np.ndarray,
        ranked_path: np.ndarray,
        *,
        directness_slack: float = 0.080,
    ) -> tuple[bool, bool]:
        base_path = np.asarray(base_path, dtype=np.int64)
        ranked_path = np.asarray(ranked_path, dtype=np.int64)
        if ranked_path.size < 2:
            return False, False
        if base_path.size < 2:
            return True, False
        if ranked_path.size > base_path.size:
            return False, False
        base_directness = self._path_directness_penalty(grid, base_path)
        ranked_directness = self._path_directness_penalty(grid, ranked_path)
        if ranked_directness > base_directness + float(directness_slack):
            return False, True
        return True, False

    def _ranked_orogenic_component_guard(
        self,
        grid,
        base_path: np.ndarray,
        ranked_path: np.ndarray,
        rank: np.ndarray,
        relief: np.ndarray,
        support_mask: np.ndarray | None = None,
        peer_spine_mask: np.ndarray | None = None,
        *,
        relief_slack_m: float = 120.0,
        support_neighbor_slack: float = 0.20,
        base_near_fraction_floor: float = 0.75,
    ) -> tuple[bool, str]:
        """Reject ranked orogenic paths that lose local linework support."""
        base_path = np.asarray(base_path, dtype=np.int64)
        ranked_path = np.asarray(ranked_path, dtype=np.int64)
        if ranked_path.size < 2:
            return False, "empty"
        if base_path.size < 2:
            return True, "missing_base"
        rank_arr = np.asarray(rank, dtype=np.float64)
        rel_arr = np.asarray(relief, dtype=np.float64)
        if rank_arr.shape != (grid.n,):
            rank_arr = np.zeros(grid.n, dtype=np.float64)
        if rel_arr.shape != (grid.n,):
            rel_arr = np.zeros(grid.n, dtype=np.float64)
        if support_mask is None:
            support = np.zeros(grid.n, dtype=bool)
        else:
            support = np.asarray(support_mask, dtype=bool)
            if support.shape != (grid.n,):
                support = np.zeros(grid.n, dtype=bool)
        if peer_spine_mask is None:
            peer = np.zeros(grid.n, dtype=bool)
        else:
            peer = np.asarray(peer_spine_mask, dtype=bool)
            if peer.shape != (grid.n,):
                peer = np.zeros(grid.n, dtype=bool)
        base_mask = np.zeros(grid.n, dtype=bool)
        base_mask[base_path] = True
        base_near = self._dilate_mask(grid, base_mask, passes=1)
        peer_near = (
            self._dilate_mask(grid, peer, passes=1)
            if peer.any()
            else np.zeros(grid.n, dtype=bool)
        )

        def local_metrics(path: np.ndarray) -> dict[str, float]:
            path = np.asarray(path, dtype=np.int64)
            path_set = {int(c) for c in path}
            endpoints = 0
            junctions = 0
            support_neighbors: list[int] = []
            for c0 in path:
                c = int(c0)
                degree = sum(1 for nb in grid.neighbors[c] if int(nb) in path_set)
                if degree <= 1:
                    endpoints += 1
                elif degree > 2:
                    junctions += 1
                if support.any():
                    support_neighbors.append(
                        sum(1 for nb in grid.neighbors[c] if support[int(nb)])
                    )
            return {
                "rank_mean": float(np.mean(rank_arr[path])) if path.size else 0.0,
                "relief_mean": float(np.mean(rel_arr[path])) if path.size else 0.0,
                "support_fraction": (
                    float(np.mean(support[path])) if support.any() and path.size else 1.0
                ),
                "support_neighbor_mean": (
                    float(np.mean(support_neighbors)) if support_neighbors else 0.0
                ),
                "peer_fraction": (
                    float(np.mean(peer_near[path])) if peer_near.any() and path.size else 1.0
                ),
                "endpoints": float(endpoints),
                "junctions": float(junctions),
            }

        base = local_metrics(base_path)
        ranked = local_metrics(ranked_path)
        if ranked["endpoints"] > base["endpoints"] + 1.0e-9:
            return False, "endpoint"
        if ranked["junctions"] > base["junctions"] + 1.0e-9:
            return False, "endpoint"
        base_near_fraction = (
            float(np.mean(base_near[ranked_path])) if ranked_path.size else 0.0
        )
        if base_near_fraction + 1.0e-9 < float(base_near_fraction_floor):
            return False, "support"
        if ranked["rank_mean"] <= base["rank_mean"] + 1.0e-9:
            return False, "rank"
        if ranked["relief_mean"] + float(relief_slack_m) < base["relief_mean"]:
            return False, "relief"
        if support.any():
            if ranked["support_fraction"] + 1.0e-9 < base["support_fraction"]:
                return False, "support"
            if (
                ranked["support_neighbor_mean"] + float(support_neighbor_slack)
                < base["support_neighbor_mean"]
            ):
                return False, "support"
        if (
            peer_near.any()
            and ranked["peer_fraction"] + 1.0e-9 < base["peer_fraction"]
        ):
            return False, "peer"
        return True, "accepted"

    def _terrain_province(self, world, surface, sea_level, crust_type,
                          crust_domain, crust_origin, crust_stability,
                          sediment=None):
        grid = world.grid
        province = np.zeros(grid.n, dtype=np.float64)
        ocean = surface < sea_level
        cont = crust_type == 1.0
        width = self._mask_width_steps(grid, cont)
        rel = surface - sea_level
        thick = world.get_field("crust.thickness_m", 0.0)
        orog_age = np.asarray(
            world.get_field("tectonics.orogeny_age_myr", -1.0),
            dtype=np.float64,
        )
        volcanism_age = np.asarray(
            world.get_field("tectonics.volcanism_age_myr", -1.0),
            dtype=np.float64,
        )
        basement_expr = self._basement_province_expression(
            world, crust_type, crust_domain, crust_stability, width,
            sediment=sediment)
        basement_shield = basement_expr["shield"]
        basement_platform = basement_expr["platform"] | basement_expr["sag_basin"]
        stable_craton = (
            cont
            & (
                ((crust_domain == DOMAIN_CRATON) & (crust_stability > 0.82))
                | basement_shield
            )
        )
        recent_orogen = cont & (
            orog_age >= max(float(world.time_myr) - 800.0, 0.0)
        ) & ~stable_craton
        recent_volcanism = cont & (
            volcanism_age >= max(float(world.time_myr) - 500.0, 0.0)
        )
        deform = self._deformation_sources(world, crust_type)
        has_deform = bool(deform["active"].any())
        deform_orogen_influence = self._band_influence(
            grid, deform["orogen_active"], passes=3)
        recent_orogen_active = (
            recent_orogen & (deform_orogen_influence >= 0.18)
            if has_deform else recent_orogen
        )
        suture_process = self._tectonic_process_mask(
            world, "suture", object_kinds=("collision",))
        active_process = (
            self._tectonic_process_mask(world, "active_margin")
            | deform["active_margin"]
            | deform["orogen_active"]
        )
        active_belt = self._band_influence(
            grid, recent_orogen_active | suture_process | active_process, passes=2)
        thick_highland_cut = (
            float(np.percentile(thick[cont], 82)) if cont.any() else float("inf")
        )
        suture = cont & (crust_domain == DOMAIN_SUTURE)
        lip = cont & (crust_domain == DOMAIN_LIP)
        active_suture_highland = suture & (
            (
                recent_orogen_active
                & (
                    ((active_belt >= 0.30) & (rel > 1800.0))
                    | (rel > 2200.0)
                )
            )
            | ((width <= 2.0) & (active_belt >= 0.45) & (rel > 1900.0))
            | ((thick >= thick_highland_cut) & (active_belt >= 0.30) & (rel > 2400.0))
        )
        lip_highland = lip & (
            (recent_volcanism & (rel > 1200.0))
            | ((rel > 2100.0) & (thick >= thick_highland_cut))
            | ((active_belt >= 0.35) & (rel > 1700.0))
        )
        plateau_highland = (
            cont
            & (width >= 3.0)
            & (rel > 2600.0)
            & (
                (active_belt >= 0.30)
                | recent_orogen_active
                | lip_highland
                | (
                    (thick >= thick_highland_cut)
                    & (crust_stability < 0.72)
                    & (active_belt >= 0.24)
                )
            )
        )
        province[ocean] = 0.0
        province[cont & (crust_domain == DOMAIN_CRATON)] = 1.0
        province[
            cont
            & (
                (crust_domain == DOMAIN_CONTINENTAL_INTERIOR)
                | (width >= 4.0)
                | basement_platform
            )
            & (crust_domain != DOMAIN_CRATON)
        ] = 2.0
        province[basement_shield] = 1.0
        province[
            cont
            & ((crust_domain == DOMAIN_CONTINENTAL_MARGIN) | (width <= 2.0))
            & (crust_domain != DOMAIN_CRATON)
        ] = 3.0
        province[cont & (crust_domain == DOMAIN_ACCRETED_TERRANE)] = 4.0
        province[suture] = np.where(
            active_suture_highland[suture],
            5.0,
            np.where(width[suture] <= 2.0, 3.0, 2.0),
        )
        province[lip] = np.where(lip_highland[lip], 6.0, 2.0)
        province[plateau_highland] = 7.0
        province[(crust_type == 0.0) & (surface >= sea_level)] = 8.0
        return province

    def _continental_detail_province(self, world, surface, sea_level, crust_type,
                                     crust_domain, crust_origin, crust_stability,
                                     orog_age=None, sediment=None):
        grid = world.grid
        detail = np.zeros(grid.n, dtype=np.float64)
        cont = crust_type == 1.0
        if not cont.any():
            return detail
        width = self._mask_width_steps(grid, cont)
        rel = surface - sea_level
        thick = world.get_field("crust.thickness_m", 0.0)
        platform_subsidence = np.clip(
            np.nan_to_num(
                world.get_field("tectonics.platform_subsidence", 0.0),
                nan=0.0, posinf=1.0, neginf=0.0,
            ),
            0.0,
            1.0,
        )
        if orog_age is None:
            orog_age = world.get_field("tectonics.orogeny_age_myr", -1.0)
        else:
            orog_age = np.asarray(orog_age, dtype=np.float64)
        age = world.get_field("crust.age_myr", 0.0)
        margin = cont & ((crust_domain == DOMAIN_CONTINENTAL_MARGIN) | (width <= 2.0))
        terrane = cont & (crust_domain == DOMAIN_ACCRETED_TERRANE)
        suture = cont & (crust_domain == DOMAIN_SUTURE)
        lip = cont & (crust_domain == DOMAIN_LIP)
        basement_expr = self._basement_province_expression(
            world, crust_type, crust_domain, crust_stability, width,
            sediment=sediment, platform_subsidence=platform_subsidence)
        basement_shield = basement_expr["shield"]
        basement_platform = basement_expr["platform"]
        basement_sag = basement_expr["sag_basin"]
        covered_old_basement = basement_expr["covered_old_basement"]
        current_shield = cont & (
            (crust_domain == DOMAIN_CRATON)
            | ((crust_stability > 0.78) & (age > 1800.0))
        )
        shield = (current_shield & ~covered_old_basement) | basement_shield
        platform = cont & (
            (crust_domain == DOMAIN_CONTINENTAL_INTERIOR)
            | (width >= 4.0)
            | basement_platform
            | basement_sag
        )
        recent_orogen = cont & (orog_age >= max(world.time_myr - 900.0, 0.0))
        old_orogen = cont & (orog_age >= 0.0) & (orog_age < max(world.time_myr - 900.0, 0.0))
        deform = self._deformation_sources(world, crust_type)
        has_deform = bool(deform["active"].any())
        suture_process = self._generalized_boundary_source(
            grid,
            self._tectonic_process_mask(world, "suture", object_kinds=("collision",))
            | deform["collision_active"],
            spacing=3,
        )
        active_process = self._generalized_boundary_source(
            grid,
            self._tectonic_process_mask(world, "active_margin")
            | deform["active_margin"]
            | deform["orogen_active"],
            spacing=2)
        suture_influence = self._band_influence(grid, suture_process, passes=5)
        active_influence = self._band_influence(grid, active_process, passes=4)
        deform_orogen_influence = self._band_influence(
            grid, deform["orogen_active"], passes=3)
        recent_orogen_active = (
            recent_orogen & (deform_orogen_influence >= 0.18)
            if has_deform else recent_orogen
        )
        suture_active_gate = (
            (recent_orogen_active | (deform_orogen_influence >= 0.18))
            if has_deform else np.ones(grid.n, dtype=bool)
        )
        active_orogenic_belt = (
            ((suture_influence >= 0.38) & suture_active_gate)
            | ((active_influence >= 0.38) & recent_orogen_active)
            | (recent_orogen_active & suture & (thick >= CONT_THICK + 9000.0))
            | deform["orogen_core"]
        )
        orogenic_response = self._orogenic_response_state(
            world, surface, sea_level, crust_type, crust_domain,
            crust_stability, orog_age=orog_age)

        detail[cont] = CONT_DETAIL_PLATFORM
        detail[shield] = CONT_DETAIL_SHIELD
        detail[margin & (rel < 700.0)] = CONT_DETAIL_RIFT_BASIN
        detail[terrane | ((crust_type == 0.0) & (surface >= sea_level))] = (
            CONT_DETAIL_ARC_MICROCONTINENT)
        if cont.any():
            thick_cut = float(np.percentile(thick[cont], 90))
            thick_highland_cut = float(np.percentile(thick[cont], 78))
            thin_cut = float(np.percentile(thick[cont], 35))
            median_thick = float(np.percentile(thick[cont], 50))
            basin_thickness_cut = min(thin_cut, median_thick - 1200.0)
            plateau_candidate = (
                cont
                & (width >= 4.0)
                & (
                    ((rel > 2500.0) & active_orogenic_belt)
                    | (lip & (rel > 1700.0))
                    | (
                        active_orogenic_belt
                        & (rel > 1900.0)
                        & (thick >= thick_highland_cut)
                    )
                    | (
                        (thick >= thick_cut)
                        & (crust_stability > 0.45)
                        & (rel > 1850.0)
                        & (active_orogenic_belt | (rel > 3000.0))
                    )
                )
            )
            plateau_width = self._mask_width_steps(grid, plateau_candidate)
            min_plateau_core_width = 2.0 if grid.n <= 3000 else 3.0
            plateau = plateau_candidate & (plateau_width >= min_plateau_core_width)
            recent_orogen_rel_floor = 1250.0 if grid.n <= 3000 else 1450.0
            recent_active_orogen_detail = (
                active_orogenic_belt
                & recent_orogen_active
                & (width >= 2.0)
                & (rel > recent_orogen_rel_floor)
                & ~shield
                & ~lip
            )
            orogen_detail = (
                (
                    (
                        active_orogenic_belt
                        & (width >= 3.0)
                        & (
                            (rel > 1800.0)
                            | ((rel > 1450.0) & (thick >= thick_highland_cut))
                        )
                    )
                    | (
                        old_orogen
                        & (suture_influence >= 0.24)
                        & (rel > 1250.0)
                        & (width >= 3.0)
                    )
                    | recent_active_orogen_detail
                )
                & ~plateau
            )
            detail[orogen_detail] = CONT_DETAIL_OROGEN
            interior_candidate = (
                platform
                & (width >= 3.0)
                & ~shield
                & ~suture
                & ~terrane
                & ~lip
                & ~orogen_detail
            )
            if interior_candidate.any():
                interior_rel_cut = max(
                    900.0,
                    float(np.percentile(rel[interior_candidate], 35)),
                )
                interior_thick_cut = min(
                    float(np.percentile(thick[interior_candidate], 65)),
                    basin_thickness_cut + 1000.0,
                )
            else:
                interior_rel_cut = 900.0
                interior_thick_cut = basin_thickness_cut
            sag_basin = (
                interior_candidate
                & (rel <= interior_rel_cut)
                & (thick <= interior_thick_cut)
                & (crust_stability < 0.88)
            )
            tectonic_subsidence_basin = (
                interior_candidate
                & (platform_subsidence >= 0.42)
                & (rel < max(1500.0, interior_rel_cut + 250.0))
                & (crust_stability < 0.92)
            )
            basin = (
                platform
                & (thick <= basin_thickness_cut)
                & (rel < 900.0)
                & (crust_stability < 0.72)
                & ~suture
                & ~lip
            ) | sag_basin | tectonic_subsidence_basin | basement_sag | (
                orogenic_response["foreland_basin_candidate"]
                & ~plateau
                & ~orogen_detail
                & ~shield
            )
            detail[basin] = CONT_DETAIL_BASIN
            detail[plateau] = CONT_DETAIL_PLATEAU
            detail[orogen_detail] = CONT_DETAIL_OROGEN
            cont_area = float(grid.cell_area[cont].sum())
            suture_fraction = (
                float(grid.cell_area[suture].sum() / max(cont_area, 1.0))
                if cont_area > 0.0 else 0.0
            )
            if suture_fraction > 0.35:
                thick_excess = np.clip(
                    (thick - (CONT_THICK + 10000.0)) / 14000.0, 0.0, 1.0)
                highland_floor = 1700.0 + 900.0 * thick_excess
                overpaint = (
                    suture
                    & np.isin(detail, [CONT_DETAIL_OROGEN, CONT_DETAIL_PLATEAU])
                    & (rel < highland_floor)
                )
                detail[overpaint] = CONT_DETAIL_PLATFORM
        return detail

    def _continental_landform_objects(self, world, surface, sea_level, crust_type,
                                      crust_domain, crust_origin, crust_stability,
                                      continental_detail, sediment,
                                      orog_age=None,
                                      passive_margin_lowland=None) -> list[dict]:
        grid = world.grid
        area = grid.cell_area
        total_area = max(float(area.sum()), 1e-12)
        cont = crust_type == 1.0
        if not cont.any():
            return []

        detail = continental_detail.astype(int)
        rel = surface - sea_level
        width = self._mask_width_steps(grid, cont)
        crust_thick = world.get_field("crust.thickness_m", 0.0)
        if orog_age is None:
            orog_age = world.get_field("tectonics.orogeny_age_myr", -1.0)
        else:
            orog_age = np.asarray(orog_age, dtype=np.float64)
        rift_potential = world.get_field("tectonics.rift_potential", 0.0)
        continent_id = world.get_field("tectonics.continent_id", -1.0)
        active_orogen_cut = max(float(world.time_myr) - 650.0, 0.0)
        recent_orogen = cont & (orog_age >= active_orogen_cut)
        old_orogen = cont & (orog_age >= 0.0) & (orog_age < active_orogen_cut)
        deform = self._deformation_sources(world, crust_type)

        rift_objects = np.zeros(grid.n, dtype=bool)
        for obj in world.objects.get("tectonics.rift_systems", []):
            rift_objects |= self._cell_mask(grid, obj.get("cells", []))

        orogenic_response = self._orogenic_response_state(
            world, surface, sea_level, crust_type, crust_domain,
            crust_stability, orog_age=orog_age, continental_detail=detail)
        orogen_source = orogenic_response["orogen_source"]
        orogen_core = cont & (detail == CONT_DETAIL_OROGEN)
        foreland_influence = orogenic_response["orogenic_load"]
        recent_loading_influence = orogenic_response["recent_loading_influence"]
        sediment_values = sediment[cont]
        sediment_cut = float(np.percentile(sediment_values, 65)) if cont.any() else np.inf
        sediment_background = (
            float(np.percentile(sediment_values, 50)) if cont.any() else np.inf
        )
        sediment_max = float(np.max(sediment_values)) if cont.any() else np.inf
        foreland_sediment_cut = max(sediment_cut, sediment_background + 250.0)
        platform_like = cont & np.isin(
            detail,
            [CONT_DETAIL_PLATFORM, CONT_DETAIL_BASIN],
        )
        platform_foreland = cont & (detail == CONT_DETAIL_PLATFORM)
        foreland_lowland = (
            cont
            & (width >= 2.0)
            & ~np.isin(crust_domain, [DOMAIN_SUTURE, DOMAIN_LIP])
            & ~np.isin(detail, [CONT_DETAIL_BASIN, CONT_DETAIL_OROGEN,
                                CONT_DETAIL_ARC_MICROCONTINENT])
        )
        foreland_rel_cut = (
            max(1250.0, float(np.percentile(rel[cont], 55))) if cont.any() else 1250.0
        )
        basin_foreland = (
            cont
            & (detail == CONT_DETAIL_BASIN)
            & (foreland_influence > 0.50)
            & (recent_loading_influence > 0.35)
        )
        foreland_basin = (
            (
                platform_foreland
                | foreland_lowland
                | basin_foreland
                | orogenic_response["foreland_basin_candidate"]
            )
            & (foreland_influence > 0.20)
            & (recent_loading_influence > 0.12)
            & (sediment >= foreland_sediment_cut)
            & (rel < foreland_rel_cut)
            & ~orogen_core
        )
        old_orogen_core = (
            old_orogen
            & (width >= 2.0)
            & (rel > 500.0)
            & ~foreland_basin
            & (detail != CONT_DETAIL_BASIN)
        )
        old_orogen_influence = self._band_influence(
            grid, old_orogen_core, passes=2)
        old_subdued_orogen = (
            old_orogen_core
            | (
                cont
                & (old_orogen_influence > 0.28)
                & (width >= 2.0)
                & (rel > 420.0)
                & ~foreland_basin
                & ~recent_orogen
                & ~np.isin(detail, [CONT_DETAIL_RIFT_BASIN,
                                    CONT_DETAIL_BASIN,
                                    CONT_DETAIL_ARC_MICROCONTINENT])
            )
            | (
                cont
                & (orog_age >= 0.0)
                & (foreland_influence > 0.35)
                & (width >= 2.0)
                & (rel > 520.0)
                & (rel < 2200.0)
                & ~foreland_basin
                & ~np.isin(detail, [CONT_DETAIL_OROGEN, CONT_DETAIL_RIFT_BASIN,
                                    CONT_DETAIL_PLATEAU,
                                    CONT_DETAIL_BASIN,
                                    CONT_DETAIL_ARC_MICROCONTINENT])
            )
            | (
                cont
                & (detail == CONT_DETAIL_OROGEN)
                & (width >= 2.0)
                & (rel > 1200.0)
                & (crust_stability >= 0.78)
                & ~foreland_basin
                & ~deform["orogen_core"]
                & ~deform["collision_active"]
            )
        )
        rift_basin = (
            (detail == CONT_DETAIL_RIFT_BASIN)
            | (
                cont
                & (width >= 3.0)
                & (rel < 900.0)
                & (
                    (rift_potential > 0.55)
                    | self._dilate_mask(grid, rift_objects | deform["rift_axis"], passes=1)
                )
            )
        )
        inactive_rift_min_width = 2.0 if grid.n <= 3000 else 3.0
        inactive_rift_sag_pool = (
            cont
            & (detail == CONT_DETAIL_RIFT_BASIN)
            & (width >= inactive_rift_min_width)
            & (rift_potential < 0.48)
            & (
                (~foreland_basin & (foreland_influence < 0.75))
                | (recent_loading_influence < 0.25)
            )
            & ~recent_orogen
            & ~np.isin(crust_domain, [DOMAIN_SUTURE, DOMAIN_ACCRETED_TERRANE,
                                      DOMAIN_LIP])
        )
        interior_candidate = (
            cont
            & (width >= 2.0)
            & ~recent_orogen
            & (foreland_influence < 0.18)
            & ~np.isin(crust_domain, [DOMAIN_SUTURE, DOMAIN_ACCRETED_TERRANE,
                                      DOMAIN_LIP])
            & ~np.isin(detail, [CONT_DETAIL_SHIELD, CONT_DETAIL_OROGEN,
                                CONT_DETAIL_RIFT_BASIN, CONT_DETAIL_PLATEAU,
                                CONT_DETAIL_ARC_MICROCONTINENT])
        )
        if interior_candidate.any():
            interior_rel_cut = max(
                900.0,
                float(np.percentile(rel[interior_candidate], 40)),
            )
            interior_sediment_cut = max(
                float(np.percentile(sediment[cont], 65)),
                float(np.percentile(sediment[cont], 50)) + 300.0,
            )
            interior_thick_cut = float(np.percentile(crust_thick[interior_candidate], 70))
        else:
            interior_rel_cut = 900.0
            interior_sediment_cut = np.inf
            interior_thick_cut = -np.inf
        interior_sag_basin = (
            interior_candidate
            & (rel <= interior_rel_cut)
            & (sediment >= interior_sediment_cut)
            & (crust_thick <= interior_thick_cut)
            & (crust_stability < 0.92)
            & ~foreland_basin
        )
        detail_basin_cells = cont & (detail == CONT_DETAIL_BASIN)
        if platform_like.any():
            stable_platform_pool = (
                platform_like
                & ~foreland_basin
                & ~rift_basin
                & ~old_subdued_orogen
                & (width >= 2.0)
                & ~np.isin(detail, [CONT_DETAIL_OROGEN,
                                    CONT_DETAIL_ARC_MICROCONTINENT])
            )
            if stable_platform_pool.any():
                platform_source = stable_platform_pool
            else:
                platform_source = platform_like
            platform_rel_cut = max(
                1200.0,
                float(np.percentile(rel[platform_source], 35)),
            )
            platform_sediment_cut = max(
                float(np.percentile(sediment[platform_source], 65)),
                float(np.percentile(sediment[platform_source], 50)) + 300.0,
            )
            platform_thick_cut = float(np.percentile(crust_thick[platform_source], 65))
            sag_depots = (
                stable_platform_pool
                & ~foreland_basin
                & (width >= 2.0)
                & (rel <= platform_rel_cut)
                & (sediment >= platform_sediment_cut)
                & (crust_thick <= platform_thick_cut)
                & (crust_stability < 0.95)
                & ~np.isin(detail, [CONT_DETAIL_OROGEN, CONT_DETAIL_ARC_MICROCONTINENT])
            )
            if sag_depots.any():
                sag_envelope = (
                    self._dilate_mask(grid, sag_depots, passes=1)
                    & stable_platform_pool
                    & ~foreland_basin
                    & (width >= 2.0)
                    & (rel <= max(platform_rel_cut + 300.0, 1500.0))
                    & (sediment >= max(
                        0.0, float(np.percentile(sediment[platform_source], 25)) - 120.0))
                    & (crust_thick <= float(np.percentile(
                        crust_thick[platform_source], 78)))
                    & (crust_stability < 0.97)
                    & ~np.isin(detail, [CONT_DETAIL_OROGEN,
                                        CONT_DETAIL_ARC_MICROCONTINENT])
                )
                interior_sag_basin |= sag_depots | sag_envelope
        detail_basin_seed = detail_basin_cells | interior_sag_basin
        basin_components = self._components(grid, detail_basin_seed)
        has_object_sized_basin = any(comp.size >= 2 for comp in basin_components)
        if not has_object_sized_basin and platform_like.any():
            mature_platform_pool = (
                platform_like
                & ~foreland_basin
                & ~rift_basin
                & (width >= 2.0)
                & ~np.isin(detail, [CONT_DETAIL_OROGEN, CONT_DETAIL_PLATEAU,
                                    CONT_DETAIL_ARC_MICROCONTINENT])
            )
            if mature_platform_pool.any():
                mature_rel_cut = max(
                    1150.0,
                    float(np.percentile(rel[mature_platform_pool], 45)),
                )
                mature_sediment_cut = max(
                    float(np.percentile(sediment[mature_platform_pool], 60)),
                    sediment_background + 20.0,
                )
                mature_thick_cut = float(np.percentile(
                    crust_thick[mature_platform_pool], 85))
                # Mature collages can host broad post-orogenic sag basins even
                # when their crust remains thick; require low relief and
                # above-background sediment so this does not become a generic
                # platform overpaint.
                mature_sag = (
                    mature_platform_pool
                    & (rel <= mature_rel_cut)
                    & (sediment >= mature_sediment_cut)
                    & (crust_thick <= mature_thick_cut)
                    & (crust_stability < 0.98)
                )
                if mature_sag.any():
                    mature_envelope = (
                        self._dilate_mask(grid, mature_sag, passes=1)
                        & mature_platform_pool
                        & (rel <= max(mature_rel_cut + 260.0, 1450.0))
                        & (sediment >= max(
                            0.0,
                            float(np.percentile(sediment[mature_platform_pool], 40)),
                        ))
                        & (crust_thick <= float(np.percentile(
                            crust_thick[mature_platform_pool], 90)))
                        & (crust_stability < 0.98)
                    )
                    interior_sag_basin |= mature_sag | mature_envelope
        if inactive_rift_sag_pool.any():
            rift_sag_rel_cut = max(
                850.0,
                float(np.percentile(rel[inactive_rift_sag_pool], 45)),
            )
            rift_sag_sediment_cut = max(
                float(np.percentile(sediment[inactive_rift_sag_pool], 55)),
                sediment_background + 120.0,
            )
            rift_sag_seed = (
                inactive_rift_sag_pool
                & (rel <= rift_sag_rel_cut)
                & (sediment >= rift_sag_sediment_cut)
                & (crust_stability < 0.92)
            )
            if rift_sag_seed.any():
                rift_sag_envelope = (
                    self._dilate_mask(grid, rift_sag_seed, passes=1)
                    & inactive_rift_sag_pool
                    & (rel <= max(rift_sag_rel_cut + 220.0, 1150.0))
                    & (sediment >= max(
                        0.0,
                        float(np.percentile(sediment[inactive_rift_sag_pool], 35)),
                    ))
                    & (crust_stability < 0.94)
                )
                interior_sag_basin |= rift_sag_seed | rift_sag_envelope
        old_subdued_orogen &= ~interior_sag_basin
        interior_basin = (
            (detail == CONT_DETAIL_BASIN)
            | interior_sag_basin
        )
        rift_basin &= ~interior_basin
        if passive_margin_lowland is None:
            passive_margin_lowland = self._passive_margin_lowland_state(
                world, surface, sea_level, crust_type, crust_domain,
                crust_stability, sediment=sediment)["mask"]
        else:
            passive_margin_lowland = np.asarray(passive_margin_lowland, dtype=bool)
        passive_margin_lowland = (
            cont
            & passive_margin_lowland
            & ~foreland_basin
            & ~old_subdued_orogen
            & ~orogen_core
        )

        masks: list[tuple[str, np.ndarray, str, tuple[str, ...]]] = [
            ("shield",
             cont & (detail == CONT_DETAIL_SHIELD),
             "cratonization_and_long_term_stability",
             ("tectonics.shields", "tectonics.cratons")),
            ("orogen",
             cont & (detail == CONT_DETAIL_OROGEN) & ~old_subdued_orogen,
             "recent_collision_or_subduction",
             ("tectonics.sutures", "tectonics.boundary_objects",
              "tectonics.closing_margins", "tectonics.deforming_networks")),
            ("old_subdued_orogen",
             old_subdued_orogen,
             "eroded_orogen",
             ("tectonics.sutures", "tectonics.boundary_objects")),
            ("foreland_basin",
             foreland_basin,
             "flexural_loading_by_orogen",
             ("tectonics.sutures", "tectonics.boundary_objects",
              "tectonics.deforming_networks")),
            ("passive_margin_lowland",
             passive_margin_lowland,
             "passive_margin_subsidence_and_coastal_plain_sedimentation",
             ("tectonics.passive_margins", "tectonics.rift_systems")),
            ("rift_basin",
             rift_basin,
             "continental_extension",
             ("tectonics.rift_systems", "tectonics.boundary_objects",
              "tectonics.deforming_networks")),
            ("plateau",
             cont & (detail == CONT_DETAIL_PLATEAU),
             "crustal_thickening_or_lip",
             ("tectonics.lips", "tectonics.boundary_objects")),
            ("interior_basin",
             cont & interior_basin,
             "intracontinental_subsidence_and_sedimentation",
             ("tectonics.interior_basins", "tectonics.platforms",
              "tectonics.cratons", "tectonics.continents")),
            ("platform",
             cont & (detail == CONT_DETAIL_PLATFORM),
             "stable_continental_interior",
             ("tectonics.platforms", "tectonics.shields",
              "tectonics.cratons", "tectonics.continents")),
            ("arc_microcontinent",
             cont & (detail == CONT_DETAIL_ARC_MICROCONTINENT),
             "arc_accretion",
             ("tectonics.terranes", "tectonics.boundary_objects")),
        ]

        kind_priority = {
            "orogen": 0,
            "old_subdued_orogen": 1,
            "foreland_basin": 2,
            "passive_margin_lowland": 3,
            "rift_basin": 4,
            "plateau": 5,
            "shield": 6,
            "interior_basin": 7,
            "platform": 8,
            "arc_microcontinent": 9,
        }
        assigned = np.zeros(grid.n, dtype=bool)
        objects: list[dict] = []
        for kind, mask, parent_process, object_sets in masks:
            clean = np.asarray(mask, dtype=bool) & cont & ~assigned
            if not clean.any():
                continue
            for comp_index, comp in enumerate(self._components(grid, clean)):
                if comp.size < 2:
                    continue
                comp_mask = np.zeros(grid.n, dtype=bool)
                comp_mask[comp] = True
                cell_area = area[comp]
                comp_area = max(float(cell_area.sum()), 1e-12)
                lat, lon = self._centroid_lat_lon(grid, comp)
                elevations = rel[comp]
                parent_continents = sorted(
                    int(x) for x in np.unique(continent_id[comp].astype(int))
                    if int(x) >= 0
                )
                parent_mask = comp_mask
                if kind == "foreland_basin":
                    parent_mask = self._dilate_mask(grid, comp_mask, passes=4)
                parent_objects = self._related_object_ids(
                    world, parent_mask, object_sets,
                    expand_passes=6,
                    nearest_max_deg=45.0)
                objects.append({
                    "id": f"{kind}:{int(comp.min())}:{comp_index}",
                    "type": "continental_landform",
                    "kind": kind,
                    "priority": int(kind_priority[kind]),
                    "parent_process": parent_process,
                    "parent_continent_ids": parent_continents,
                    "parent_tectonic_object_ids": parent_objects,
                    "cell_count": int(comp.size),
                    "area_fraction": float(comp_area / total_area),
                    "centroid_lat": lat,
                    "centroid_lon": lon,
                    "mean_elevation_m": float(np.average(elevations, weights=cell_area)),
                    "elevation_p90_m": float(np.percentile(elevations, 90)),
                    "relief_p90_minus_p10_m": float(
                        np.percentile(elevations, 90) - np.percentile(elevations, 10)),
                    "mean_sediment_m": float(np.average(sediment[comp], weights=cell_area)),
                    "width_p50_steps": float(np.percentile(width[comp], 50)),
                    "mean_stability": float(
                        np.average(crust_stability[comp], weights=cell_area)),
                    "cells": comp.astype(int).tolist() if comp.size <= 600 else [],
                })
                assigned[comp] = True
        objects.sort(key=lambda obj: (-obj["area_fraction"], obj["priority"], obj["id"]))
        return self._stabilize_process_objects(
            world,
            "terrain.continental_landforms",
            objects,
            id_prefix="landform",
        )

    def _p11168_parent_orogen_hierarchy_masks(
        self,
        world,
        surface,
        sea_level,
        crust_type,
        active_orogen_mask,
        active_orogen_score,
    ) -> dict[str, np.ndarray]:
        """Compile guarded crest/branch/foreland masks from parent linework.

        P111.6.7 creates ordered convergent/subduction parent lines in the
        tectonics layer.  This first terrain-side coupling pass keeps the
        response semantic rather than directly uplifting cells: it records a
        narrow orogenic hierarchy field that later passes can use as a guarded
        authority for mountain-belt repair.
        """
        grid = world.grid
        n = grid.n
        area = np.asarray(grid.cell_area, dtype=np.float64)
        total_area = max(float(area.sum()), 1.0e-12)
        rel = np.asarray(surface, dtype=np.float64) - float(sea_level)
        crust = np.asarray(crust_type, dtype=np.float64)
        if rel.shape != (n,) or crust.shape != (n,):
            rel = np.zeros(n, dtype=np.float64)
            crust = np.zeros(n, dtype=np.float64)
        cont_land = (crust == 1.0) & (rel >= 0.0)
        active = np.asarray(active_orogen_mask, dtype=bool)
        score = np.asarray(active_orogen_score, dtype=np.float64)
        if active.shape != (n,):
            active = np.zeros(n, dtype=bool)
        if score.shape != (n,):
            score = rel.copy()

        parent = np.zeros(n, dtype=bool)
        convergent_parent = np.zeros(n, dtype=bool)
        subduction_parent = np.zeros(n, dtype=bool)
        for obj in world.objects.get("tectonics.boundary_objects", []):
            kind = str(obj.get("kind", ""))
            if kind not in {"convergent_parent", "subduction_parent"}:
                continue
            cells = self._cell_mask(grid, obj.get("cells", ()))
            parent |= cells
            if kind == "convergent_parent":
                convergent_parent |= cells
            elif kind == "subduction_parent":
                subduction_parent |= cells
        for obj in world.objects.get("tectonics.boundary_polylines", []):
            kind = str(obj.get("kind", ""))
            boundary_kind = str(obj.get("boundary_kind", ""))
            if kind == "convergent_parent_polyline" or boundary_kind == "convergent_parent":
                cells = self._cell_mask(grid, obj.get("cells", ()))
                parent |= cells
                convergent_parent |= cells
            elif kind == "subduction_parent_polyline" or boundary_kind == "subduction_parent":
                cells = self._cell_mask(grid, obj.get("cells", ()))
                parent |= cells
                subduction_parent |= cells

        def parent_corridor_objects(
            trunk_mask: np.ndarray,
            branch_mask: np.ndarray,
            foreland_mask: np.ndarray,
            *,
            id_prefix: str = "p146:parent_orogen_corridor",
            schema: str = "aevum.p146_parent_orogen_corridor.v1",
            source_parent_group_id: str = "",
            parent_boundary_kind: str = "",
            parent_plate_ids: tuple[int, ...] = (),
        ) -> list[dict[str, object]]:
            corridor = (
                np.asarray(trunk_mask, dtype=bool)
                | np.asarray(branch_mask, dtype=bool)
                | np.asarray(foreland_mask, dtype=bool)
            )
            objects: list[dict[str, object]] = []
            for idx, comp in enumerate(self._components(grid, corridor)):
                comp = np.asarray(comp, dtype=np.int64)
                if comp.size == 0:
                    continue
                comp_mask = np.zeros(n, dtype=bool)
                comp_mask[comp] = True
                trunk_cells = np.where(comp_mask & trunk_mask)[0]
                branch_cells = np.where(comp_mask & branch_mask)[0]
                foreland_cells = np.where(comp_mask & foreland_mask)[0]
                obj: dict[str, object] = {
                    "id": f"{id_prefix}:{idx}",
                    "schema": schema,
                    "type": "parent_orogen_corridor",
                    "kind": "parent_orogen_corridor",
                    "cells": comp.astype(int).tolist(),
                    "trunk_cells": trunk_cells.astype(int).tolist(),
                    "branch_cells": branch_cells.astype(int).tolist(),
                    "foreland_cells": foreland_cells.astype(int).tolist(),
                    "cell_count": int(comp.size),
                    "trunk_cell_count": int(trunk_cells.size),
                    "branch_cell_count": int(branch_cells.size),
                    "foreland_cell_count": int(foreland_cells.size),
                }
                if source_parent_group_id:
                    obj["source_parent_group_id"] = source_parent_group_id
                if parent_boundary_kind:
                    obj["parent_boundary_kind"] = parent_boundary_kind
                if parent_plate_ids:
                    obj["parent_plate_ids"] = [int(x) for x in parent_plate_ids]
                objects.append(obj)
            return objects

        def parent_corridor_group_specs(
        ) -> tuple[list[dict[str, object]], int, int]:
            """Collect parent-orogen groups before raster hierarchy.

            P147 keeps the identity of ordered boundary polylines when present.
            Boundary objects are used only when no ordered parent polyline is
            available, which avoids double-counting the same tectonic source.
            """
            groups: list[dict[str, object]] = []
            seen: set[tuple[str, str]] = set()

            def clean_cells(raw_cells) -> np.ndarray:
                cells = np.asarray(raw_cells, dtype=np.int64)
                cells = cells[(cells >= 0) & (cells < n)]
                return np.unique(cells)

            polyline_count = 0
            for obj in world.objects.get("tectonics.boundary_polylines", []):
                kind = str(obj.get("kind", ""))
                boundary_kind = str(obj.get("boundary_kind", ""))
                if (
                    kind not in {
                        "convergent_parent_polyline",
                        "subduction_parent_polyline",
                    }
                    and boundary_kind not in {
                        "convergent_parent",
                        "subduction_parent",
                    }
                ):
                    continue
                cells = clean_cells(obj.get("cells", ()))
                if cells.size < 2:
                    continue
                group_kind = (
                    boundary_kind
                    if boundary_kind in {"convergent_parent", "subduction_parent"}
                    else kind.replace("_polyline", "")
                )
                source_id = str(obj.get("id", f"polyline:{group_kind}:{polyline_count}"))
                key = ("polyline", source_id)
                if key in seen:
                    continue
                seen.add(key)
                plate_ids = tuple(
                    int(x) for x in obj.get("parent_plate_ids", ())
                    if int(x) >= 0
                )
                groups.append({
                    "id": source_id,
                    "source": "polyline",
                    "kind": group_kind,
                    "cells": cells,
                    "cell_count": int(cells.size),
                    "parent_plate_ids": plate_ids,
                    "source_boundary_object_id": str(
                        obj.get("source_boundary_object_id", "")),
                })
                polyline_count += 1

            if groups:
                groups.sort(key=lambda item: (
                    -int(item.get("cell_count", 0)),
                    str(item.get("kind", "")),
                    str(item.get("id", "")),
                ))
                max_groups = max(1, int(world.g(
                    "terrain.p147_parent_orogen_corridor_max_groups",
                    12.0,
                )))
                return groups[:max_groups], int(len(groups[:max_groups])), 0

            object_count = 0
            for obj in world.objects.get("tectonics.boundary_objects", []):
                kind = str(obj.get("kind", ""))
                if kind not in {"convergent_parent", "subduction_parent"}:
                    continue
                cells = clean_cells(obj.get("cells", ()))
                if cells.size < 2:
                    continue
                source_id = str(obj.get("id", f"object:{kind}:{object_count}"))
                key = ("object", source_id)
                if key in seen:
                    continue
                seen.add(key)
                plate_ids = tuple(
                    int(x) for x in obj.get("parent_plate_ids", ())
                    if int(x) >= 0
                )
                groups.append({
                    "id": source_id,
                    "source": "object",
                    "kind": kind,
                    "cells": cells,
                    "cell_count": int(cells.size),
                    "parent_plate_ids": plate_ids,
                    "source_boundary_object_id": source_id,
                })
                object_count += 1
            groups.sort(key=lambda item: (
                -int(item.get("cell_count", 0)),
                str(item.get("kind", "")),
                str(item.get("id", "")),
            ))
            max_groups = max(1, int(world.g(
                "terrain.p147_parent_orogen_corridor_max_groups",
                12.0,
            )))
            return groups[:max_groups], 0, int(len(groups[:max_groups]))

        def cap_mask(mask: np.ndarray, max_fraction: float,
                     rank: np.ndarray) -> np.ndarray:
            clean = np.asarray(mask, dtype=bool) & cont_land
            if not clean.any():
                return clean
            budget = max(float(max_fraction) * total_area, float(area[clean].min()))
            if float(area[clean].sum()) <= budget:
                return clean
            cells = np.where(clean)[0]
            ordered = cells[np.argsort(-rank[cells])]
            chosen: list[int] = []
            used_area = 0.0
            for c in ordered:
                chosen.append(int(c))
                used_area += float(area[int(c)])
                if used_area >= budget:
                    break
            out = np.zeros(n, dtype=bool)
            out[np.asarray(chosen, dtype=np.int64)] = True
            return out & clean

        def cap_mask_preserving_components(
            mask: np.ndarray,
            max_fraction: float,
            rank: np.ndarray,
        ) -> np.ndarray:
            clean = np.asarray(mask, dtype=bool) & cont_land
            if not clean.any():
                return clean
            budget = max(float(max_fraction) * total_area, float(area[clean].min()))
            if float(area[clean].sum()) <= budget:
                return clean

            rank_arr = np.asarray(rank, dtype=np.float64)
            if rank_arr.shape != (n,):
                rank_arr = np.zeros(n, dtype=np.float64)
            components = self._components(grid, clean)
            records: list[tuple[float, float, int, np.ndarray]] = []
            for comp in components:
                comp = np.asarray(comp, dtype=np.int64)
                if comp.size == 0:
                    continue
                comp_area = float(area[comp].sum())
                comp_score = float(np.average(rank_arr[comp], weights=area[comp]))
                records.append((comp_score, comp_area, int(comp.size), comp))
            records.sort(key=lambda item: (item[0], item[1], item[2]), reverse=True)

            out = np.zeros(n, dtype=bool)
            used_area = 0.0

            def add_connected_subset(comp: np.ndarray, remaining: float) -> float:
                if remaining <= 0.0 or comp.size == 0:
                    return 0.0
                comp_mask = np.zeros(n, dtype=bool)
                comp_mask[comp] = True
                seed = int(comp[np.argmax(rank_arr[comp])])
                queued = np.zeros(n, dtype=bool)
                selected = np.zeros(n, dtype=bool)
                heap: list[tuple[float, int]] = [(-float(rank_arr[seed]), seed)]
                queued[seed] = True
                added_area = 0.0
                while heap and added_area < remaining:
                    _neg_rank, cell = heapq.heappop(heap)
                    if selected[cell]:
                        continue
                    cell_area = float(area[cell])
                    if added_area > 0.0 and added_area + cell_area > remaining:
                        continue
                    selected[cell] = True
                    added_area += cell_area
                    for nb0 in grid.neighbors[cell]:
                        nb = int(nb0)
                        if not comp_mask[nb] or queued[nb] or selected[nb]:
                            continue
                        heapq.heappush(heap, (-float(rank_arr[nb]), nb))
                        queued[nb] = True
                out[selected] = True
                return added_area

            for _score_mean, comp_area, _size, comp in records:
                remaining = budget - used_area
                if remaining <= 0.0:
                    break
                if comp_area <= remaining:
                    out[comp] = True
                    used_area += comp_area
                    continue
                used_area += add_connected_subset(comp, remaining)
                break
            return out & clean

        def hierarchy_class_profile(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
        ) -> dict[str, float]:
            def component_stats(mask: np.ndarray) -> tuple[int, float, float]:
                mask_bool = np.asarray(mask, dtype=bool) & cont_land
                mask_area = float(area[mask_bool].sum())
                if mask_area <= 0.0:
                    return 0, 0.0, 0.0
                comps = self._components(grid, mask_bool)
                comp_areas = sorted(
                    (float(area[comp].sum()) for comp in comps),
                    reverse=True,
                )
                small_area = sum(
                    float(area[comp].sum())
                    for comp in comps
                    if comp.size <= 8
                )
                top3_share = float(np.clip(
                    sum(comp_areas[:3]) / max(mask_area, 1.0e-12),
                    0.0,
                    1.0,
                ))
                return (
                    int(len(comps)),
                    float(np.clip(small_area / mask_area, 0.0, 1.0)),
                    top3_share,
                )

            crest_bool = np.asarray(crest_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool) & cont_land & ~crest_bool
            )
            peak_bool = crest_bool | branch_bool
            crest_components, crest_small, crest_top3 = component_stats(crest_bool)
            branch_components, branch_small, branch_top3 = component_stats(branch_bool)
            peak_components = len(self._components(grid, peak_bool))
            class_small = max(crest_small, branch_small)
            class_components = crest_components + branch_components
            component_factor = max(
                float(class_components) / max(float(peak_components), 1.0),
                1.0,
            )
            top3 = min(crest_top3, branch_top3) if branch_bool.any() else crest_top3
            class_score = float(np.clip(
                top3 * (1.0 - 0.55 * class_small) / component_factor,
                0.0,
                1.0,
            ))
            return {
                "class_linework_score": class_score,
                "class_small_area_fraction": class_small,
                "crest_component_count": float(crest_components),
                "branch_component_count": float(branch_components),
                "peak_component_count": float(peak_components),
                "crest_small_area_fraction": crest_small,
                "branch_small_area_fraction": branch_small,
                "top3": top3,
            }

        def bridge_peak_hierarchy(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
            foreland_mask: np.ndarray,
            parent_core_mask: np.ndarray,
            parent_near_mask: np.ndarray,
            max_fraction: float,
        ) -> tuple[np.ndarray, np.ndarray, np.ndarray]:
            line = (
                np.asarray(crest_mask, dtype=bool)
                | np.asarray(branch_mask, dtype=bool)
            ) & cont_land
            support = (
                cont_land
                & parent_near_mask
                & ~np.asarray(foreland_mask, dtype=bool)
                & (
                    line
                    | self._dilate_mask(grid, active & cont_land, passes=1)
                    | (rel >= 260.0)
                )
            )
            if not line.any() or not support.any():
                return crest_mask.copy(), branch_mask.copy(), np.zeros(n, dtype=bool)

            budget = max(float(max_fraction) * total_area, float(area[line].min()))
            bridge = np.zeros(n, dtype=bool)
            used_area = 0.0
            foreland_bool = np.asarray(foreland_mask, dtype=bool)
            for support_comp in self._components(grid, support):
                comp_mask = np.zeros(n, dtype=bool)
                comp_mask[support_comp] = True
                line_comps = self._components(grid, line & comp_mask)
                if len(line_comps) < 2:
                    continue
                reps: list[int] = []
                for comp in line_comps:
                    reps.append(int(comp[np.argmax(score[comp])]))
                reps_arr = np.asarray(reps, dtype=np.int64)
                comp_cells = np.asarray(support_comp, dtype=np.int64)
                lat_span = float(np.ptp(grid.lat[comp_cells])) if comp_cells.size > 1 else 0.0
                lon_values = (
                    np.asarray(grid.lon[comp_cells], dtype=np.float64) + 360.0
                ) % 360.0
                lon_values.sort()
                lon_gaps = np.diff(np.r_[lon_values, lon_values[0] + 360.0])
                lon_span = float(360.0 - lon_gaps.max(initial=0.0))
                mean_lat = float(np.mean(grid.lat[comp_cells])) if comp_cells.size else 0.0
                zonal_span = lon_span * max(float(np.cos(np.deg2rad(mean_lat))), 0.25)
                axis_values = (
                    (grid.lon[reps_arr] + 360.0) % 360.0
                    if zonal_span >= lat_span else grid.lat[reps_arr]
                )
                ordered = reps_arr[np.argsort(axis_values)]
                for a, b in zip(ordered[:-1], ordered[1:]):
                    if used_area >= budget:
                        break
                    path = self._shortest_path_within_mask(
                        grid,
                        int(a),
                        int(b),
                        support,
                        max_steps=18,
                    )
                    if path.size < 2 or path.size > 18:
                        continue
                    cells = path[
                        ~line[path]
                        & ~bridge[path]
                        & ~foreland_bool[path]
                    ]
                    if cells.size == 0:
                        continue
                    scores = (
                        score[cells]
                        + 120.0 * parent_core_mask[cells].astype(np.float64)
                        + 45.0 * self._same_neighbor_count(grid, line | bridge)[cells]
                    )
                    for c in cells[np.argsort(-scores)]:
                        if used_area + float(area[int(c)]) > budget:
                            break
                        bridge[int(c)] = True
                        used_area += float(area[int(c)])
                if used_area >= budget:
                    break

            if not bridge.any():
                return crest_mask.copy(), branch_mask.copy(), bridge
            crest_bridge = bridge & parent_core_mask & (rel >= 600.0)
            branch_bridge = bridge & ~crest_bridge
            refined_crest = (np.asarray(crest_mask, dtype=bool) | crest_bridge) & cont_land
            refined_branch = (
                (np.asarray(branch_mask, dtype=bool) | branch_bridge)
                & cont_land
                & ~refined_crest
            )
            return refined_crest, refined_branch, bridge

        def refine_hierarchy_geometry(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
            foreland_mask: np.ndarray,
            parent_near_mask: np.ndarray,
        ) -> tuple[np.ndarray, np.ndarray, np.ndarray, np.ndarray, np.ndarray]:
            crest_bool = np.asarray(crest_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool) & cont_land & ~crest_bool
            )
            foreland_bool = (
                np.asarray(foreland_mask, dtype=bool)
                & cont_land
                & ~crest_bool
                & ~branch_bool
            )
            peak = crest_bool | branch_bool
            branch_extension = np.zeros(n, dtype=bool)
            if peak.any():
                peak_near = self._dilate_mask(grid, peak, passes=2)
                branch_neighbor_count = self._same_neighbor_count(grid, branch_bool)
                crest_neighbor_count = self._same_neighbor_count(grid, crest_bool)
                branch_anchor = branch_neighbor_count >= 1
                if not branch_bool.any():
                    branch_anchor |= crest_neighbor_count >= 2
                shoulder_support = (
                    cont_land
                    & parent_near_mask
                    & peak_near
                    & branch_anchor
                    & ~crest_bool
                    & ~branch_bool
                    & ~foreland_bool
                    & (rel >= 1600.0)
                    & (rel <= 3400.0)
                    & (self._same_neighbor_count(grid, peak) >= 1)
                )
                if shoulder_support.any():
                    shoulder_rank = (
                        score
                        + 0.20 * np.clip(rel, 0.0, 3600.0)
                        + 85.0 * self._same_neighbor_count(grid, peak)
                    )
                    branch_extension = cap_mask(shoulder_support, 0.006, shoulder_rank)
                    branch_bool = (
                        branch_bool | (branch_extension & ~crest_bool)
                    ) & cont_land
                    peak = crest_bool | branch_bool

            removed_foreland = np.zeros(n, dtype=bool)
            if foreland_bool.any():
                if peak.any():
                    foreland_support = self._dilate_mask(grid, peak, passes=4)
                    refined_foreland = (
                        foreland_bool
                        & foreland_support
                        & ~crest_bool
                        & ~branch_bool
                    )
                else:
                    refined_foreland = np.zeros(n, dtype=bool)
                removed_foreland = foreland_bool & ~refined_foreland
                foreland_bool = refined_foreland

            return (
                crest_bool,
                branch_bool,
                foreland_bool,
                branch_extension,
                removed_foreland,
            )

        def component_axis_values(cells: np.ndarray) -> np.ndarray:
            cells = np.asarray(cells, dtype=np.int64)
            if cells.size == 0:
                return np.asarray([], dtype=np.float64)
            lat_span = float(np.ptp(grid.lat[cells])) if cells.size > 1 else 0.0
            lon_values = (np.asarray(grid.lon[cells], dtype=np.float64) + 360.0) % 360.0
            if lon_values.size > 1:
                order = np.argsort(lon_values)
                sorted_lon = lon_values[order]
                gaps = np.diff(np.r_[sorted_lon, sorted_lon[0] + 360.0])
                start = int((np.argmax(gaps) + 1) % sorted_lon.size)
                origin = float(sorted_lon[start])
                lon_unwrapped = (lon_values - origin + 360.0) % 360.0
                lon_span = float(360.0 - gaps.max(initial=0.0))
            else:
                lon_unwrapped = lon_values
                lon_span = 0.0
            mean_lat = float(np.mean(grid.lat[cells])) if cells.size else 0.0
            zonal_span = lon_span * max(float(np.cos(np.deg2rad(mean_lat))), 0.25)
            return lon_unwrapped if zonal_span >= lat_span else np.asarray(grid.lat[cells])

        def build_parent_orogen_corridors(
            parent_core_mask: np.ndarray,
            parent_near_mask: np.ndarray,
            parent_outer_mask: np.ndarray,
            max_fraction: float,
            parent_line_mask: np.ndarray | None = None,
        ) -> tuple[np.ndarray, np.ndarray, np.ndarray, np.ndarray, int]:
            """Initialize continuous parent-orogen corridor zones.

            P146 provides an object-level skeleton before the older hierarchy
            raster passes run.  It is intentionally conservative: generated
            cells remain inside parent-supported continental land and are later
            re-capped by the existing crest/branch/foreland budget gates.
            """
            parent_core_bool = np.asarray(parent_core_mask, dtype=bool)
            parent_near_bool = np.asarray(parent_near_mask, dtype=bool)
            parent_outer_bool = np.asarray(parent_outer_mask, dtype=bool)
            parent_line_bool = (
                parent
                if parent_line_mask is None
                else np.asarray(parent_line_mask, dtype=bool)
            )
            source = (
                cont_land
                & parent_core_bool
                & (
                    active
                    | (score >= 350.0)
                    | (rel >= 450.0)
                )
            )
            if not source.any():
                source = cont_land & parent_near_bool & active
            if not source.any():
                return (
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    0,
                )

            support = (
                cont_land
                & parent_near_bool
                & (
                    active
                    | source
                    | (score >= 250.0)
                    | (rel >= 80.0)
                )
            )
            if not support.any():
                support = source.copy()
            budget = max(
                float(max_fraction) * total_area,
                float(area[source].min()),
            )
            trunk_bridge = np.zeros(n, dtype=bool)
            used_area = 0.0
            bridge_path_count = 0
            rank = (
                score
                + 0.24 * np.clip(rel, 0.0, 4200.0)
                + 180.0 * parent_core_bool.astype(np.float64)
                + 90.0 * parent_line_bool.astype(np.float64)
            )
            for comp in self._components(grid, support):
                if used_area >= budget:
                    break
                comp = np.asarray(comp, dtype=np.int64)
                comp_mask = np.zeros(n, dtype=bool)
                comp_mask[comp] = True
                source_parts = self._components(grid, source & comp_mask)
                if len(source_parts) < 2:
                    continue
                reps = np.asarray([
                    int(part[np.argmax(rank[part])])
                    for part in source_parts
                ], dtype=np.int64)
                ordered = reps[np.argsort(component_axis_values(reps))]
                max_steps = max(10, min(48, int(comp.size) + 8))
                for a, b in zip(ordered[:-1], ordered[1:]):
                    if used_area >= budget:
                        break
                    path = self._ranked_shortest_path_within_mask(
                        grid,
                        int(a),
                        int(b),
                        support,
                        rank,
                        max_steps=max_steps,
                    )
                    if path.size < 2 or path.size > max_steps:
                        continue
                    cells = path[~source[path] & ~trunk_bridge[path]]
                    if cells.size == 0:
                        continue
                    cell_area = float(area[cells].sum())
                    if used_area + cell_area > budget:
                        continue
                    trunk_bridge[cells] = True
                    used_area += cell_area
                    bridge_path_count += 1

            trunk_raw = source | trunk_bridge
            trunk_rank = rank + 140.0 * trunk_bridge.astype(np.float64)
            trunk = cap_mask(trunk_raw, 0.020, trunk_rank)
            trunk_near = self._dilate_mask(grid, trunk, passes=1)
            trunk_wide = self._dilate_mask(grid, trunk, passes=3)
            branch_candidate = (
                cont_land
                & parent_near_bool
                & ~trunk
                & (
                    active
                    | trunk_near
                    | (self._same_neighbor_count(grid, trunk) >= 1)
                )
                & (rel >= 250.0)
                & (rel <= 3400.0)
            )
            branch_rank = (
                score
                + 0.18 * np.clip(rel, 0.0, 3600.0)
                + 100.0 * trunk_near.astype(np.float64)
                + 60.0 * self._same_neighbor_count(grid, trunk)
            )
            branch = cap_mask(branch_candidate, 0.024, branch_rank) & ~trunk
            peak = trunk | branch
            peak_neighbor_count = self._same_neighbor_count(grid, peak)
            foreland_candidate = (
                cont_land
                & parent_outer_bool
                & ~peak
                & trunk_wide
                & (peak_neighbor_count >= 1)
                & (rel >= 20.0)
                & (rel <= 2200.0)
            )
            foreland_rank = (
                1800.0
                - np.abs(np.clip(rel, 0.0, 2200.0) - 650.0)
                + 115.0 * peak_neighbor_count
                + 0.08 * np.clip(score, 0.0, 2200.0)
            )
            foreland = cap_mask(
                foreland_candidate,
                0.026,
                foreland_rank,
            ) & ~peak
            return trunk, branch, foreland, trunk_bridge & trunk, bridge_path_count

        def prune_parent_orogen_corridor_components(
            trunk_mask: np.ndarray,
            branch_mask: np.ndarray,
            foreland_mask: np.ndarray,
            bridge_mask: np.ndarray,
            max_components: int,
            parent_line_mask: np.ndarray | None = None,
        ) -> tuple[np.ndarray, np.ndarray, np.ndarray, np.ndarray, int, int]:
            corridor = (
                np.asarray(trunk_mask, dtype=bool)
                | np.asarray(branch_mask, dtype=bool)
                | np.asarray(foreland_mask, dtype=bool)
            ) & cont_land
            components = self._components(grid, corridor)
            component_count = len(components)
            if component_count <= max_components:
                return (
                    np.asarray(trunk_mask, dtype=bool) & cont_land,
                    np.asarray(branch_mask, dtype=bool) & cont_land,
                    np.asarray(foreland_mask, dtype=bool) & cont_land,
                    np.asarray(bridge_mask, dtype=bool) & cont_land,
                    component_count,
                    0,
                )

            total_cells = int(np.count_nonzero(corridor))
            min_supported_cells = max(3, int(np.ceil(total_cells * 0.035)))
            records: list[tuple[float, int, int, int, int, int, np.ndarray]] = []
            trunk_bool = np.asarray(trunk_mask, dtype=bool)
            branch_bool = np.asarray(branch_mask, dtype=bool)
            foreland_bool = np.asarray(foreland_mask, dtype=bool)
            bridge_bool = np.asarray(bridge_mask, dtype=bool)
            parent_line_bool = (
                parent
                if parent_line_mask is None
                else np.asarray(parent_line_mask, dtype=bool)
            )
            trunk_neighbor_count = self._same_neighbor_count(grid, trunk_bool)
            peak_neighbor_count = self._same_neighbor_count(
                grid, trunk_bool | branch_bool)
            for idx, comp in enumerate(components):
                comp = np.asarray(comp, dtype=np.int64)
                if comp.size == 0:
                    continue
                trunk_count = int(np.count_nonzero(trunk_bool[comp]))
                branch_count = int(np.count_nonzero(branch_bool[comp]))
                foreland_count = int(np.count_nonzero(foreland_bool[comp]))
                bridge_count = int(np.count_nonzero(bridge_bool[comp]))
                supported_count = trunk_count + branch_count + foreland_count
                near_trunk_count = int(np.count_nonzero(
                    trunk_neighbor_count[comp] > 0))
                near_peak_count = int(np.count_nonzero(
                    peak_neighbor_count[comp] > 0))
                if trunk_count <= 0 and near_peak_count <= 0:
                    continue
                if supported_count < min_supported_cells and (
                    trunk_count < 2 and near_peak_count < 2
                ):
                    continue
                parent_count = int(np.count_nonzero(parent_line_bool[comp]))
                cross_section_bonus = min(branch_count, foreland_count)
                component_score = (
                    8.0 * trunk_count
                    + 4.0 * bridge_count
                    + 3.0 * branch_count
                    + 2.0 * foreland_count
                    + 2.5 * parent_count
                    + 2.0 * near_trunk_count
                    + 1.5 * near_peak_count
                    + 4.0 * cross_section_bonus
                    + 0.002 * float(np.mean(score[comp]))
                    + 0.001 * float(np.mean(np.clip(rel[comp], 0.0, 4200.0)))
                )
                records.append((
                    component_score,
                    int(comp.size),
                    idx,
                    trunk_count,
                    branch_count,
                    foreland_count,
                    comp,
                ))

            if not records:
                empty = np.zeros(n, dtype=bool)
                return empty, empty.copy(), empty.copy(), empty.copy(), 0, component_count

            records.sort(key=lambda item: (item[0], item[1]), reverse=True)
            kept_records = records[:max_components]
            kept_ids = {int(item[2]) for item in kept_records}
            for count_index in (4, 5):
                if any(int(item[count_index]) > 0 for item in kept_records):
                    continue
                replacement = next(
                    (item for item in records
                     if int(item[count_index]) > 0
                     and int(item[2]) not in kept_ids),
                    None,
                )
                if replacement is None:
                    continue
                if len(kept_records) < max_components:
                    kept_records.append(replacement)
                    kept_ids.add(int(replacement[2]))
                    continue
                weakest_index = min(
                    range(len(kept_records)),
                    key=lambda i: (kept_records[i][0], kept_records[i][1]),
                )
                kept_ids.discard(int(kept_records[weakest_index][2]))
                kept_records[weakest_index] = replacement
                kept_ids.add(int(replacement[2]))
            keep = np.zeros(n, dtype=bool)
            for _, _, _, _, _, _, comp in kept_records:
                keep[comp] = True
            retained_count = len(self._components(grid, corridor & keep))
            pruned_count = max(component_count - retained_count, 0)
            return (
                trunk_bool & keep,
                branch_bool & keep,
                foreland_bool & keep,
                bridge_bool & keep,
                retained_count,
                pruned_count,
            )

        def repair_parent_group_trunk_candidate(
            trunk_mask: np.ndarray,
            branch_mask: np.ndarray,
            foreland_mask: np.ndarray,
            bridge_mask: np.ndarray,
            group_parent_mask: np.ndarray,
            group_core_mask: np.ndarray,
            group_near_mask: np.ndarray,
        ) -> tuple[
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            bool,
            bool,
            int,
            int,
            dict[str, float],
            dict[str, float],
        ]:
            """Repair fragmented P147 group trunks before global trial scoring."""
            trunk_bool = np.asarray(trunk_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool) & cont_land & ~trunk_bool
            )
            foreland_bool = (
                np.asarray(foreland_mask, dtype=bool)
                & cont_land
                & ~trunk_bool
                & ~branch_bool
            )
            bridge_bool = np.asarray(bridge_mask, dtype=bool) & trunk_bool
            empty_branch = np.zeros(n, dtype=bool)
            before_profile = hierarchy_class_profile(trunk_bool, empty_branch)
            after_profile = before_profile
            if not trunk_bool.any():
                return (
                    trunk_bool,
                    branch_bool,
                    foreland_bool,
                    bridge_bool,
                    False,
                    False,
                    0,
                    0,
                    before_profile,
                    after_profile,
                )

            before_small = float(before_profile["class_small_area_fraction"])
            before_score = float(before_profile["class_linework_score"])
            trunk_components = self._components(grid, trunk_bool)
            fragmented = before_small >= 0.999 and len(trunk_components) > 1
            if not fragmented:
                return (
                    trunk_bool,
                    branch_bool,
                    foreland_bool,
                    bridge_bool,
                    False,
                    False,
                    0,
                    0,
                    before_profile,
                    after_profile,
                )

            parent_bool = np.asarray(group_parent_mask, dtype=bool)
            core_bool = np.asarray(group_core_mask, dtype=bool)
            near_bool = np.asarray(group_near_mask, dtype=bool)
            trunk_near = self._dilate_mask(grid, trunk_bool, passes=1)
            allowed = (
                cont_land
                & near_bool
                & (rel <= 4300.0)
                & (
                    core_bool
                    | parent_bool
                    | trunk_near
                    | active
                    | (score >= 100.0)
                )
            )
            allowed |= trunk_bool
            if not allowed.any():
                return (
                    trunk_bool,
                    branch_bool,
                    foreland_bool,
                    bridge_bool,
                    False,
                    True,
                    0,
                    0,
                    before_profile,
                    after_profile,
                )

            rank = (
                score
                + 0.20 * np.clip(rel, 0.0, 3800.0)
                + 180.0 * parent_bool.astype(np.float64)
                + 150.0 * core_bool.astype(np.float64)
                + 120.0 * trunk_bool.astype(np.float64)
            )
            reps = np.asarray([
                int(comp[np.argmax(rank[comp])])
                for comp in trunk_components
            ], dtype=np.int64)
            ordered = reps[np.argsort(component_axis_values(reps))]
            bridge_budget = max(
                float(p150_group_trunk_bridge_max_fraction) * total_area,
                float(area[trunk_bool].min()),
            )
            max_steps = max(8, int(p150_group_trunk_bridge_max_steps))
            bridge_add = np.zeros(n, dtype=bool)
            used_area = 0.0
            path_count = 0
            for a, b in zip(ordered[:-1], ordered[1:]):
                if used_area >= bridge_budget:
                    break
                path = self._ranked_shortest_path_within_mask(
                    grid,
                    int(a),
                    int(b),
                    allowed,
                    rank,
                    max_steps=max_steps,
                )
                if path.size < 2 or path.size > max_steps:
                    continue
                cells = path[~trunk_bool[path] & ~bridge_add[path]]
                if cells.size == 0:
                    continue
                cell_area = float(area[cells].sum())
                if cell_area <= 0.0 or used_area + cell_area > bridge_budget:
                    continue
                bridge_add[cells] = True
                used_area += cell_area
                path_count += 1

            if not bridge_add.any():
                return (
                    trunk_bool,
                    branch_bool,
                    foreland_bool,
                    bridge_bool,
                    False,
                    True,
                    0,
                    0,
                    before_profile,
                    after_profile,
                )

            repaired_trunk = trunk_bool | bridge_add
            after_profile = hierarchy_class_profile(repaired_trunk, empty_branch)
            after_small = float(after_profile["class_small_area_fraction"])
            after_score = float(after_profile["class_linework_score"])
            small_improved = after_small < before_small - 1.0e-9
            score_safe = after_score + 0.005 >= before_score
            target_safe = (
                after_small
                <= float(p150_group_trunk_max_class_small_area_fraction) + 1.0e-9
            )
            if not (small_improved and score_safe and target_safe):
                return (
                    trunk_bool,
                    branch_bool,
                    foreland_bool,
                    bridge_bool,
                    False,
                    True,
                    int(np.count_nonzero(bridge_add)),
                    int(path_count),
                    before_profile,
                    after_profile,
                )

            branch_bool = branch_bool & ~repaired_trunk
            foreland_bool = foreland_bool & ~repaired_trunk & ~branch_bool
            return (
                repaired_trunk,
                branch_bool,
                foreland_bool,
                (bridge_bool | bridge_add) & repaired_trunk,
                True,
                False,
                int(np.count_nonzero(bridge_add)),
                int(path_count),
                before_profile,
                after_profile,
            )

        def refine_branch_spine_continuity(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
            foreland_mask: np.ndarray,
            parent_core_mask: np.ndarray,
            parent_near_mask: np.ndarray,
            max_fraction: float,
        ) -> tuple[np.ndarray, np.ndarray, np.ndarray, int]:
            crest_bool = np.asarray(crest_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool)
                & cont_land
                & ~crest_bool
            )
            foreland_bool = (
                np.asarray(foreland_mask, dtype=bool)
                & cont_land
                & ~crest_bool
                & ~branch_bool
            )
            peak = crest_bool | branch_bool
            candidate = np.zeros(n, dtype=bool)
            if not peak.any() or not branch_bool.any():
                return branch_bool.copy(), np.zeros(n, dtype=bool), candidate, 0

            peak_near = self._dilate_mask(grid, peak, passes=1)
            parent_core_bool = np.asarray(parent_core_mask, dtype=bool)
            parent_near_bool = np.asarray(parent_near_mask, dtype=bool)
            candidate = (
                cont_land
                & parent_near_bool
                & ~foreland_bool
                & ~peak
                & (rel >= 620.0)
                & (rel <= 3350.0)
                & (
                    parent_core_bool
                    | peak_near
                    | (self._same_neighbor_count(grid, peak) >= 1)
                )
            )
            support = peak | candidate
            if not candidate.any() or not support.any():
                return branch_bool.copy(), np.zeros(n, dtype=bool), candidate, 0

            budget = max(
                float(max_fraction) * total_area,
                float(area[candidate].min()),
            )
            bridge = np.zeros(n, dtype=bool)
            used_area = 0.0
            path_count = 0
            rank = (
                score
                + 0.22 * np.clip(rel, 0.0, 3600.0)
                + 140.0 * crest_bool.astype(np.float64)
                + 90.0 * branch_bool.astype(np.float64)
                + 120.0 * parent_core_bool.astype(np.float64)
            )
            for support_comp in self._components(grid, support):
                if used_area >= budget:
                    break
                comp_mask = np.zeros(n, dtype=bool)
                comp_mask[support_comp] = True
                peak_comps = self._components(grid, peak & comp_mask)
                if len(peak_comps) < 2:
                    continue
                reps = [
                    int(comp[np.argmax(rank[comp])])
                    for comp in peak_comps
                ]
                reps_arr = np.asarray(reps, dtype=np.int64)
                ordered = reps_arr[np.argsort(component_axis_values(reps_arr))]
                max_steps = max(10, min(34, int(support_comp.size) + 4))
                for a, b in zip(ordered[:-1], ordered[1:]):
                    if used_area >= budget:
                        break
                    path = self._shortest_path_within_mask(
                        grid,
                        int(a),
                        int(b),
                        support,
                        max_steps=max_steps,
                    )
                    if path.size < 2 or path.size > max_steps:
                        continue
                    cells = path[candidate[path] & ~bridge[path]]
                    if cells.size == 0:
                        continue
                    path_count += 1
                    cell_scores = (
                        rank[cells]
                        + 85.0 * self._same_neighbor_count(
                            grid, peak | bridge)[cells]
                    )
                    for c in cells[np.argsort(-cell_scores)]:
                        cell_area = float(area[int(c)])
                        if used_area + cell_area > budget:
                            break
                        bridge[int(c)] = True
                        used_area += cell_area
                if used_area >= budget:
                    break

            refined_branch = (
                (branch_bool | bridge)
                & cont_land
                & ~crest_bool
                & ~foreland_bool
            )
            before_peak_components = len(self._components(grid, peak))
            after_peak_components = len(
                self._components(grid, crest_bool | refined_branch))
            before_branch_components = len(self._components(grid, branch_bool))
            after_branch_components = len(self._components(grid, refined_branch))
            if (
                bridge.any()
                and after_peak_components > before_peak_components
            ) or (
                bridge.any()
                and after_peak_components == before_peak_components
                and after_branch_components > before_branch_components + 1
            ):
                return branch_bool.copy(), np.zeros(n, dtype=bool), candidate, 0
            return refined_branch, bridge, candidate, path_count

        p1141_ranked_path_used_count = 0
        p1141_ranked_path_changed_count = 0
        p1141_ranked_path_extra_step_count = 0
        p1142_ranked_path_guard_rejected_count = 0
        p1142_ranked_path_directness_rejected_count = 0
        p1144_ranked_path_component_guard_rejected_count = 0
        p1144_ranked_path_rank_rejected_count = 0
        p1144_ranked_path_relief_rejected_count = 0
        p1144_ranked_path_support_rejected_count = 0
        p1144_ranked_path_peer_rejected_count = 0
        p1144_ranked_path_endpoint_rejected_count = 0

        def derive_spine(
            mask: np.ndarray,
            rank: np.ndarray,
            *,
            support_mask: np.ndarray | None = None,
            peer_spine_mask: np.ndarray | None = None,
        ) -> np.ndarray:
            nonlocal p1141_ranked_path_used_count
            nonlocal p1141_ranked_path_changed_count
            nonlocal p1141_ranked_path_extra_step_count
            nonlocal p1142_ranked_path_guard_rejected_count
            nonlocal p1142_ranked_path_directness_rejected_count
            nonlocal p1144_ranked_path_component_guard_rejected_count
            nonlocal p1144_ranked_path_rank_rejected_count
            nonlocal p1144_ranked_path_relief_rejected_count
            nonlocal p1144_ranked_path_support_rejected_count
            nonlocal p1144_ranked_path_peer_rejected_count
            nonlocal p1144_ranked_path_endpoint_rejected_count
            clean = np.asarray(mask, dtype=bool) & cont_land
            spine = np.zeros(n, dtype=bool)
            if not clean.any():
                return spine
            support_bool = (
                np.asarray(support_mask, dtype=bool)
                if support_mask is not None
                else clean
            )
            if support_bool.shape != (n,):
                support_bool = clean
            support_bool = support_bool & cont_land
            peer_bool = (
                np.asarray(peer_spine_mask, dtype=bool)
                if peer_spine_mask is not None
                else np.zeros(n, dtype=bool)
            )
            if peer_bool.shape != (n,):
                peer_bool = np.zeros(n, dtype=bool)
            for comp in self._components(grid, clean):
                comp = np.asarray(comp, dtype=np.int64)
                if comp.size <= 2:
                    spine[comp] = True
                    continue
                axis = component_axis_values(comp)
                start = int(comp[int(np.argmin(axis))])
                end = int(comp[int(np.argmax(axis))])
                comp_mask = np.zeros(n, dtype=bool)
                comp_mask[comp] = True
                path = self._shortest_path_within_mask(
                    grid,
                    start,
                    end,
                    comp_mask,
                    max_steps=max(6, min(96, int(comp.size) + 4)),
                )
                if world.g("terrain.enable_p1141_ranked_orogenic_spine_paths", 0.0) > 0.0:
                    ranked_path = self._ranked_shortest_path_within_mask(
                        grid,
                        start,
                        end,
                        comp_mask,
                        rank,
                        max_steps=max(6, min(96, int(comp.size) + 4)),
                    )
                    if ranked_path.size >= 2:
                        p1141_ranked_path_used_count += 1
                        accept_ranked, directness_rejected = (
                            self._ranked_orogenic_path_guard(
                                grid,
                                path,
                                ranked_path,
                            )
                        )
                        if not accept_ranked and ranked_path.size > path.size:
                            p1141_ranked_path_extra_step_count += max(
                                0,
                                int(ranked_path.size) - int(path.size),
                            )
                        if not accept_ranked:
                            if directness_rejected:
                                p1142_ranked_path_directness_rejected_count += 1
                            p1142_ranked_path_guard_rejected_count += 1
                            ranked_path = path
                        if (
                            accept_ranked
                            and world.g(
                                "terrain.enable_p1144_ranked_spine_component_guard",
                                1.0,
                            ) > 0.0
                        ):
                            component_support = support_bool
                            component_peer = peer_bool & ~comp_mask
                            accept_ranked, component_reason = (
                                self._ranked_orogenic_component_guard(
                                    grid,
                                    path,
                                    ranked_path,
                                    rank,
                                    rel,
                                    component_support,
                                    component_peer,
                                )
                            )
                            if not accept_ranked:
                                p1144_ranked_path_component_guard_rejected_count += 1
                                if component_reason == "rank":
                                    p1144_ranked_path_rank_rejected_count += 1
                                elif component_reason == "relief":
                                    p1144_ranked_path_relief_rejected_count += 1
                                elif component_reason == "peer":
                                    p1144_ranked_path_peer_rejected_count += 1
                                elif component_reason == "endpoint":
                                    p1144_ranked_path_endpoint_rejected_count += 1
                                else:
                                    p1144_ranked_path_support_rejected_count += 1
                                ranked_path = path
                        if (
                            ranked_path.size != path.size
                            or not np.array_equal(ranked_path, path)
                        ):
                            p1141_ranked_path_changed_count += 1
                            p1141_ranked_path_extra_step_count += max(
                                0,
                                int(ranked_path.size) - int(path.size),
                            )
                        path = ranked_path
                if path.size >= 2:
                    spine[path] = True
                    continue
                keep = max(1, int(np.ceil(np.sqrt(float(comp.size)))))
                cells = comp[np.argsort(-rank[comp])[:keep]]
                spine[cells] = True
            return spine & clean

        def branch_attachment_fraction(
            crest_spine_mask: np.ndarray,
            branch_spine_mask: np.ndarray,
        ) -> float:
            branch_bool = np.asarray(branch_spine_mask, dtype=bool)
            if not branch_bool.any():
                return 1.0
            crest_near = self._dilate_mask(
                grid,
                np.asarray(crest_spine_mask, dtype=bool),
                passes=1,
            )
            comps = self._components(grid, branch_bool)
            if not comps:
                return 1.0
            attached = 0
            for comp in comps:
                if np.any(crest_near[comp]):
                    attached += 1
            return float(attached / max(float(len(comps)), 1.0))

        def short_component_count(mask: np.ndarray, max_size: int = 2) -> int:
            return int(sum(
                1 for comp in self._components(grid, np.asarray(mask, dtype=bool))
                if comp.size <= int(max_size)
            ))

        def smooth_spine_linework(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
            foreland_mask: np.ndarray,
            crest_spine_mask: np.ndarray,
            branch_spine_mask: np.ndarray,
            parent_core_mask: np.ndarray,
            parent_near_mask: np.ndarray,
            max_fraction: float,
        ) -> tuple[
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            int,
            bool,
        ]:
            """Join dashed spine fragments inside a parent peak hierarchy.

            The pass can add a small number of parent-supported crest/branch
            cells, but only as spine bridges, and rejects candidates that
            increase peak or spine component count.
            """
            crest_bool = np.asarray(crest_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool)
                & cont_land
                & ~crest_bool
            )
            peak = crest_bool | branch_bool
            old_crest_spine = np.asarray(crest_spine_mask, dtype=bool) & crest_bool
            old_branch_spine = (
                np.asarray(branch_spine_mask, dtype=bool)
                & branch_bool
                & ~old_crest_spine
            )
            old_spine = old_crest_spine | old_branch_spine
            if not old_spine.any() or not peak.any():
                return (
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    0,
                    False,
                )
            peak_near = self._dilate_mask(grid, peak, passes=2)
            candidate = (
                cont_land
                & ~old_spine
                & ~np.asarray(foreland_mask, dtype=bool)
                & (
                    np.asarray(parent_near_mask, dtype=bool)
                    | self._dilate_mask(grid, old_spine, passes=2)
                )
                & (
                    peak_near
                    | np.asarray(parent_core_mask, dtype=bool)
                    | (rel >= 620.0)
                    | (self._same_neighbor_count(grid, old_spine) >= 1)
                )
                & (
                    peak
                    | peak_near
                    | np.asarray(parent_core_mask, dtype=bool)
                )
                & (self._same_neighbor_count(grid, peak) >= 1)
                & (
                    (self._same_neighbor_count(grid, old_spine) >= 1)
                    | (
                        np.asarray(parent_core_mask, dtype=bool)
                        & (self._same_neighbor_count(grid, peak) >= 2)
                    )
                )
            )
            bridge = np.zeros(n, dtype=bool)
            diagnostic = candidate.copy()
            if not candidate.any():
                return (
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                    bridge,
                    diagnostic,
                    0,
                    False,
                )

            before_components = len(self._components(grid, old_spine))
            before_short = short_component_count(old_spine)
            before_branch_attachment = branch_attachment_fraction(
                old_crest_spine,
                old_branch_spine,
            )
            budget = max(
                float(max_fraction) * total_area,
                float(area[candidate].min()),
            )
            used_area = 0.0
            path_count = 0
            rank = (
                score
                + 0.24 * np.clip(rel, 0.0, 4200.0)
                + 180.0 * crest_bool.astype(np.float64)
                + 90.0 * branch_bool.astype(np.float64)
                + 130.0 * np.asarray(parent_core_mask, dtype=bool).astype(np.float64)
                + 120.0 * old_spine.astype(np.float64)
            )
            support = peak | candidate
            peak_components_before = len(self._components(grid, peak))
            for support_comp in self._components(grid, support):
                if used_area >= budget:
                    break
                comp_mask = np.zeros(n, dtype=bool)
                comp_mask[support_comp] = True
                old_parts = self._components(grid, old_spine & comp_mask)
                if len(old_parts) < 2:
                    continue
                reps = np.asarray([
                    int(comp[np.argmax(rank[comp])])
                    for comp in old_parts
                ], dtype=np.int64)
                ordered = reps[np.argsort(component_axis_values(reps))]
                max_steps = max(10, min(88, int(support_comp.size) + 6))
                for a, b in zip(ordered[:-1], ordered[1:]):
                    if used_area >= budget:
                        break
                    path = self._shortest_path_within_mask(
                        grid,
                        int(a),
                        int(b),
                        comp_mask & support,
                        max_steps=max_steps,
                    )
                    if path.size < 2 or path.size > max_steps:
                        continue
                    cells = path[
                        support[path]
                        & ~old_spine[path]
                        & ~bridge[path]
                    ]
                    if cells.size == 0 or not np.any(candidate[cells]):
                        continue
                    path_area = float(area[cells].sum())
                    if used_area + path_area > budget:
                        continue
                    bridge[cells] = True
                    used_area += path_area
                    path_count += 1

            if not bridge.any():
                return (
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                    bridge,
                    diagnostic,
                    0,
                    False,
                )

            bridge_crest = bridge & crest_bool
            new_crest = crest_bool & cont_land
            new_branch = (
                (branch_bool | (bridge & ~new_crest))
                & cont_land
                & ~new_crest
            )
            new_peak = new_crest | new_branch
            new_crest_spine = (
                old_crest_spine | (bridge & new_crest)
            ) & new_crest
            new_branch_spine = (
                (old_branch_spine | (bridge & new_branch))
                & new_branch
                & ~new_crest_spine
            )
            new_spine = new_crest_spine | new_branch_spine
            peak_components_after = len(self._components(grid, new_peak))
            after_components = len(self._components(grid, new_spine))
            after_short = short_component_count(new_spine)
            after_branch_attachment = branch_attachment_fraction(
                new_crest_spine,
                new_branch_spine,
            )
            hierarchy_area_ok = (
                float(area[new_crest].sum() / total_area) <= 0.036
                and float(area[new_branch].sum() / total_area) <= 0.042
            )
            accepted = (
                hierarchy_area_ok
                and
                peak_components_after <= peak_components_before
                and (
                    after_components < before_components
                    or (
                        after_components == before_components
                        and (
                            after_short < before_short
                            or after_branch_attachment > before_branch_attachment + 1.0e-9
                        )
                    )
                )
            )
            if not accepted:
                return (
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    diagnostic,
                    0,
                    False,
                )
            return (
                new_crest,
                new_branch,
                new_crest_spine,
                new_branch_spine,
                bridge,
                diagnostic,
                path_count,
                True,
            )

        def spine_top3_component_share(mask: np.ndarray) -> float:
            mask_bool = np.asarray(mask, dtype=bool)
            mask_area = float(area[mask_bool].sum())
            if mask_area <= 0.0:
                return 0.0
            rows = sorted(
                (
                    float(area[comp].sum())
                    for comp in self._components(grid, mask_bool)
                ),
                reverse=True,
            )
            return float(np.clip(sum(rows[:3]) / mask_area, 0.0, 1.0))

        def spine_linework_score(
            crest_spine_mask: np.ndarray,
            branch_spine_mask: np.ndarray,
            peak_mask: np.ndarray,
        ) -> float:
            return spine_linework_profile(
                crest_spine_mask,
                branch_spine_mask,
                peak_mask,
            )["score"]

        def spine_linework_profile(
            crest_spine_mask: np.ndarray,
            branch_spine_mask: np.ndarray,
            peak_mask: np.ndarray,
        ) -> dict[str, float]:
            def class_component_stats(mask: np.ndarray) -> tuple[int, float]:
                mask_bool = np.asarray(mask, dtype=bool)
                mask_area = float(area[mask_bool].sum())
                if mask_area <= 0.0:
                    return 0, 0.0
                comps = self._components(grid, mask_bool)
                small_area = sum(
                    float(area[comp].sum())
                    for comp in comps
                    if comp.size <= 8
                )
                return len(comps), float(np.clip(small_area / mask_area, 0.0, 1.0))

            crest_bool = np.asarray(crest_spine_mask, dtype=bool)
            branch_bool = np.asarray(branch_spine_mask, dtype=bool)
            spine_mask = (
                crest_bool
                | branch_bool
            )
            crest_component_count, crest_small_area_fraction = (
                class_component_stats(crest_bool))
            branch_component_count, branch_small_area_fraction = (
                class_component_stats(branch_bool))
            class_small_area_fraction = max(
                crest_small_area_fraction,
                branch_small_area_fraction,
            )
            component_count = len(self._components(grid, spine_mask))
            peak_component_count = len(
                self._components(grid, np.asarray(peak_mask, dtype=bool)))
            short_fraction = float(
                short_component_count(spine_mask) / max(float(component_count), 1.0))
            attachment = branch_attachment_fraction(
                crest_spine_mask,
                branch_spine_mask,
            )
            top3 = spine_top3_component_share(spine_mask)
            components_per_peak = float(
                component_count / max(float(peak_component_count), 1.0))
            score_value = float(np.clip(
                spine_top3_component_share(spine_mask)
                * (1.0 - 0.65 * short_fraction)
                * (0.65 + 0.35 * attachment)
                / max(components_per_peak, 1.0),
                0.0,
                1.0,
            ))
            class_linework_score = float(np.clip(
                score_value * (1.0 - 0.55 * class_small_area_fraction),
                0.0,
                1.0,
            ))
            return {
                "score": score_value,
                "component_count": float(component_count),
                "peak_component_count": float(peak_component_count),
                "short_count": float(short_component_count(spine_mask)),
                "short_fraction": short_fraction,
                "attachment": attachment,
                "top3": top3,
                "components_per_peak": components_per_peak,
                "crest_component_count": float(crest_component_count),
                "branch_component_count": float(branch_component_count),
                "crest_small_area_fraction": crest_small_area_fraction,
                "branch_small_area_fraction": branch_small_area_fraction,
                "class_small_area_fraction": class_small_area_fraction,
                "class_linework_score": class_linework_score,
            }

        def parent_aligned_spine_fraction(
            spine_mask: np.ndarray,
            parent_near_mask: np.ndarray,
        ) -> float:
            spine_bool = np.asarray(spine_mask, dtype=bool)
            if not spine_bool.any():
                return 1.0
            parent_near_bool = np.asarray(parent_near_mask, dtype=bool)
            spine_area = float(area[spine_bool].sum())
            return float(np.clip(
                float(area[spine_bool & parent_near_bool].sum())
                / max(spine_area, 1.0e-12),
                0.0,
                1.0,
            ))

        def promote_parent_anchor_spine(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
            crest_spine_mask: np.ndarray,
            branch_spine_mask: np.ndarray,
            parent_anchor_mask: np.ndarray,
            parent_core_mask: np.ndarray,
            parent_near_mask: np.ndarray,
            max_fraction: float,
        ) -> tuple[
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            bool,
            dict[str, float],
        ]:
            """Promote existing peak cells into spines when parent linework supports them."""
            crest_bool = np.asarray(crest_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool)
                & cont_land
                & ~crest_bool
            )
            old_crest_spine = (
                np.asarray(crest_spine_mask, dtype=bool) & crest_bool
            )
            old_branch_spine = (
                np.asarray(branch_spine_mask, dtype=bool)
                & branch_bool
                & ~old_crest_spine
            )
            old_spine = old_crest_spine | old_branch_spine
            peak = crest_bool | branch_bool
            parent_anchor_bool = np.asarray(parent_anchor_mask, dtype=bool)
            parent_core_bool = np.asarray(parent_core_mask, dtype=bool)
            parent_near_bool = np.asarray(parent_near_mask, dtype=bool)
            old_profile = spine_linework_profile(
                old_crest_spine,
                old_branch_spine,
                peak,
            )
            before_alignment = parent_aligned_spine_fraction(
                old_spine,
                parent_anchor_bool,
            )
            telemetry = {
                "candidate_cell_count": 0.0,
                "promoted_cell_count": 0.0,
                "alignment_fraction_before": before_alignment,
                "alignment_fraction_after": before_alignment,
                "linework_score_before": old_profile["score"],
                "linework_score_after": old_profile["score"],
                "component_count_before": old_profile["component_count"],
                "component_count_after": old_profile["component_count"],
                "short_component_count_before": old_profile["short_count"],
                "short_component_count_after": old_profile["short_count"],
            }
            if not old_spine.any() or not peak.any() or not parent_near_bool.any():
                return (
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    False,
                    telemetry,
                )

            same_spine = self._same_neighbor_count(grid, old_spine)
            candidate = (
                peak
                & ~old_spine
                & parent_near_bool
                & (same_spine >= 2)
                & (rel >= 120.0)
                & (rel <= 4200.0)
            )
            telemetry["candidate_cell_count"] = float(np.count_nonzero(candidate))
            if not candidate.any():
                return (
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    candidate,
                    False,
                    telemetry,
                )

            budget = max(
                float(max_fraction) * total_area,
                float(area[candidate].min()),
            )
            rank = (
                score
                + 0.20 * np.clip(rel, 0.0, 4200.0)
                + 320.0 * parent_anchor_bool.astype(np.float64)
                + 180.0 * parent_core_bool.astype(np.float64)
                + 110.0 * same_spine.astype(np.float64)
                + 80.0 * crest_bool.astype(np.float64)
            )
            promoted = np.zeros(n, dtype=bool)
            used_area = 0.0
            for cell in np.where(candidate)[0][np.argsort(-rank[candidate])]:
                c = int(cell)
                cell_area = float(area[c])
                if used_area + cell_area > budget:
                    continue
                promoted[c] = True
                used_area += cell_area

            if not promoted.any():
                return (
                    old_crest_spine,
                    old_branch_spine,
                    promoted,
                    candidate,
                    False,
                    telemetry,
                )

            new_crest_spine = (old_crest_spine | (promoted & crest_bool)) & crest_bool
            new_branch_spine = (
                (old_branch_spine | (promoted & branch_bool))
                & branch_bool
                & ~new_crest_spine
            )
            new_spine = new_crest_spine | new_branch_spine
            new_profile = spine_linework_profile(
                new_crest_spine,
                new_branch_spine,
                peak,
            )
            after_alignment = parent_aligned_spine_fraction(
                new_spine,
                parent_anchor_bool,
            )
            telemetry.update({
                "promoted_cell_count": float(np.count_nonzero(promoted)),
                "alignment_fraction_after": after_alignment,
                "linework_score_after": new_profile["score"],
                "component_count_after": new_profile["component_count"],
                "short_component_count_after": new_profile["short_count"],
            })
            accepted = (
                new_profile["component_count"] <= old_profile["component_count"] + 1.0e-9
                and new_profile["short_count"] <= old_profile["short_count"] + 1.0e-9
                and new_profile["score"] + 1.0e-9 >= old_profile["score"]
                and after_alignment > before_alignment + 1.0e-9
                and not np.any(new_crest_spine & new_branch_spine)
                and np.all(crest_bool[new_crest_spine])
                and np.all(branch_bool[new_branch_spine])
            )
            if not accepted:
                return (
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    candidate,
                    False,
                    telemetry,
                )
            return (
                new_crest_spine,
                new_branch_spine,
                promoted,
                candidate,
                True,
                telemetry,
            )

        def terminal_cleanup_proxy_profile(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
            crest_spine_mask: np.ndarray,
            branch_spine_mask: np.ndarray,
        ) -> dict[str, float]:
            crest_bool = np.asarray(crest_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool)
                & cont_land
                & ~crest_bool
            )
            peak = crest_bool | branch_bool
            hierarchy_values = np.zeros(n, dtype=np.float64)
            hierarchy_values[branch_bool] = 2.0
            hierarchy_values[crest_bool] = 3.0
            spine_values = np.zeros(n, dtype=np.float64)
            branch_spine_bool = (
                np.asarray(branch_spine_mask, dtype=bool)
                & branch_bool
            )
            crest_spine_bool = (
                np.asarray(crest_spine_mask, dtype=bool)
                & crest_bool
            )
            spine_values[branch_spine_bool] = 2.0
            spine_values[crest_spine_bool] = 3.0
            cleaned_spine = spine_values
            for cleanup in (
                self._p1138_terminal_spine_stub_cleanup,
                self._p1139_terminal_spine_leaf_tip_cleanup,
                self._p1140_terminal_spine_triangular_kink_cleanup,
            ):
                cleaned_candidate, cleanup_telemetry = cleanup(
                    world,
                    surface,
                    sea_level,
                    crust_type,
                    hierarchy_values,
                    cleaned_spine,
                )
                if bool(cleanup_telemetry.get("accepted", False)):
                    cleaned_spine = cleaned_candidate
            cleaned_crest_spine = crest_bool & (cleaned_spine >= 3.0)
            cleaned_branch_spine = (
                branch_bool
                & (cleaned_spine >= 2.0)
                & ~cleaned_crest_spine
            )
            return spine_linework_profile(
                cleaned_crest_spine,
                cleaned_branch_spine,
                peak,
            )

        def promote_spine_objects(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
            crest_spine_mask: np.ndarray,
            branch_spine_mask: np.ndarray,
            max_fraction: float,
        ) -> tuple[
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            int,
            bool,
        ]:
            """Promote final spine masks into smoother per-orogen path objects."""
            crest_bool = np.asarray(crest_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool)
                & cont_land
                & ~crest_bool
            )
            peak = crest_bool | branch_bool
            old_crest_spine = np.asarray(crest_spine_mask, dtype=bool) & crest_bool
            old_branch_spine = (
                np.asarray(branch_spine_mask, dtype=bool)
                & branch_bool
                & ~old_crest_spine
            )
            old_spine = old_crest_spine | old_branch_spine
            candidate = peak & ~old_spine
            bridge = np.zeros(n, dtype=bool)
            if not peak.any() or not candidate.any():
                return old_crest_spine, old_branch_spine, bridge, candidate, 0, False

            old_components = len(self._components(grid, old_spine))
            old_short = short_component_count(old_spine)
            old_attachment = branch_attachment_fraction(
                old_crest_spine,
                old_branch_spine,
            )
            old_top3 = spine_top3_component_share(old_spine)
            peak_components_for_score = len(self._components(grid, peak))
            old_short_fraction = float(old_short / max(float(old_components), 1.0))
            old_score = float(np.clip(
                old_top3
                * (1.0 - 0.65 * old_short_fraction)
                * (0.65 + 0.35 * old_attachment)
                / max(
                    float(old_components) / max(float(peak_components_for_score), 1.0),
                    1.0,
                ),
                0.0,
                1.0,
            ))
            budget = max(
                float(max_fraction) * total_area,
                float(area[candidate].min()),
            )
            used_area = 0.0
            path_count = 0
            rank = (
                score
                + 0.26 * np.clip(rel, 0.0, 4200.0)
                + 180.0 * crest_bool.astype(np.float64)
                + 95.0 * branch_bool.astype(np.float64)
                + 130.0 * old_spine.astype(np.float64)
                + 55.0 * self._same_neighbor_count(grid, old_spine)
            )

            def add_path(path: np.ndarray) -> None:
                nonlocal used_area, path_count
                if path.size < 2:
                    return
                cells = path[candidate[path] & ~bridge[path]]
                if cells.size == 0:
                    return
                path_area = float(area[cells].sum())
                if used_area + path_area > budget:
                    return
                bridge[cells] = True
                used_area += path_area
                path_count += 1

            for peak_comp in self._components(grid, peak):
                if used_area >= budget:
                    break
                comp_mask = np.zeros(n, dtype=bool)
                comp_mask[peak_comp] = True
                comp_spine = old_spine & comp_mask
                comp_candidate = candidate & comp_mask
                if not comp_candidate.any():
                    continue
                if not comp_spine.any():
                    derived = derive_spine(
                        peak & comp_mask,
                        rank + 70.0 * comp_mask.astype(np.float64),
                        support_mask=(
                            np.asarray(parent_near, dtype=bool)
                            | old_spine
                            | comp_mask
                        ),
                    )
                    cells = np.where(derived & comp_candidate & ~bridge)[0]
                    cell_area = float(area[cells].sum()) if cells.size else 0.0
                    if cells.size and used_area + cell_area <= budget:
                        bridge[cells] = True
                        used_area += cell_area
                        path_count += 1
                    continue

                spine_parts = self._components(grid, comp_spine)
                if len(spine_parts) >= 2:
                    reps = np.asarray([
                        int(comp[np.argmax(rank[comp])])
                        for comp in spine_parts
                    ], dtype=np.int64)
                    ordered = reps[np.argsort(component_axis_values(reps))]
                    max_steps = max(10, min(96, int(peak_comp.size) + 8))
                    for a, b in zip(ordered[:-1], ordered[1:]):
                        if used_area >= budget:
                            break
                        path = self._shortest_path_within_mask(
                            grid,
                            int(a),
                            int(b),
                            comp_mask & peak,
                            max_steps=max_steps,
                        )
                        add_path(path)

                crest_spine_comp = old_crest_spine & comp_mask
                if not crest_spine_comp.any():
                    continue
                crest_parts = self._components(grid, crest_spine_comp)
                crest_reps = np.asarray([
                    int(comp[np.argmax(rank[comp])])
                    for comp in crest_parts
                ], dtype=np.int64)
                crest_near = self._dilate_mask(grid, crest_spine_comp, passes=1)
                for branch_part in self._components(
                    grid,
                    old_branch_spine & comp_mask,
                ):
                    if used_area >= budget:
                        break
                    if np.any(crest_near[branch_part]):
                        continue
                    start = int(branch_part[np.argmax(rank[branch_part])])
                    if crest_reps.size == 0:
                        continue
                    dots = grid.xyz[crest_reps] @ grid.xyz[start]
                    ordered_targets = crest_reps[np.argsort(-dots)]
                    max_steps = max(8, min(80, int(peak_comp.size) + 6))
                    for target in ordered_targets:
                        path = self._shortest_path_within_mask(
                            grid,
                            start,
                            int(target),
                            comp_mask & peak,
                            max_steps=max_steps,
                        )
                        if path.size >= 2:
                            add_path(path)
                            break

            if not bridge.any():
                return old_crest_spine, old_branch_spine, bridge, candidate, 0, False
            new_crest_spine = (old_crest_spine | (bridge & crest_bool)) & crest_bool
            new_branch_spine = (
                (old_branch_spine | (bridge & branch_bool))
                & branch_bool
                & ~new_crest_spine
            )
            new_spine = new_crest_spine | new_branch_spine
            new_components = len(self._components(grid, new_spine))
            new_short = short_component_count(new_spine)
            new_attachment = branch_attachment_fraction(
                new_crest_spine,
                new_branch_spine,
            )
            new_top3 = spine_top3_component_share(new_spine)
            peak_components = len(self._components(grid, peak))
            new_short_fraction = float(new_short / max(float(new_components), 1.0))
            new_score = float(np.clip(
                new_top3
                * (1.0 - 0.65 * new_short_fraction)
                * (0.65 + 0.35 * new_attachment)
                / max(float(new_components) / max(float(peak_components), 1.0), 1.0),
                0.0,
                1.0,
            ))
            accepted = (
                new_components <= max(old_components, peak_components)
                and new_short <= old_short
                and new_short_fraction <= old_short_fraction + 1.0e-9
                and new_attachment + 1.0e-9 >= old_attachment
                and new_top3 + 1.0e-9 >= old_top3
                and new_score + 1.0e-9 >= old_score
                and not np.any(new_crest_spine & new_branch_spine)
                and np.all(crest_bool[new_crest_spine])
                and np.all(branch_bool[new_branch_spine])
                and (
                    new_components < old_components
                    or new_attachment > old_attachment + 1.0e-9
                    or new_top3 > old_top3 + 1.0e-9
                    or new_short < old_short
                    or new_score > old_score + 1.0e-9
                )
            )
            if not accepted:
                return (
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    candidate,
                    0,
                    False,
                )
            return (
                new_crest_spine,
                new_branch_spine,
                bridge,
                candidate,
                path_count,
                True,
            )

        def plan_whole_orogen_spine_mask(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
            foreland_mask: np.ndarray,
            crest_spine_mask: np.ndarray,
            branch_spine_mask: np.ndarray,
            parent_core_mask: np.ndarray,
            parent_near_mask: np.ndarray,
            max_fraction: float,
        ) -> tuple[
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            int,
            bool,
            dict[str, float],
            dict[str, float],
            dict[str, float],
        ]:
            crest_bool = np.asarray(crest_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool)
                & cont_land
                & ~crest_bool
            )
            foreland_bool = (
                np.asarray(foreland_mask, dtype=bool)
                & cont_land
                & ~crest_bool
                & ~branch_bool
            )
            old_crest_spine = np.asarray(crest_spine_mask, dtype=bool) & crest_bool
            old_branch_spine = (
                np.asarray(branch_spine_mask, dtype=bool)
                & branch_bool
                & ~old_crest_spine
            )
            old_spine = old_crest_spine | old_branch_spine
            peak = crest_bool | branch_bool
            old_profile = spine_linework_profile(
                old_crest_spine,
                old_branch_spine,
                peak,
            )
            class_repair_needed = (
                old_profile["class_small_area_fraction"] >= 0.45
                or (
                    old_profile["score"] >= 0.80
                    and old_profile["class_linework_score"] + 0.050
                    < old_profile["score"]
                )
            )
            trial_info = {
                "reject_code": 0.0,
                "support_component_count": 0.0,
                "multi_spine_support_component_count": 0.0,
                "attempted_path_count": 0.0,
                "found_path_count": 0.0,
                "bridge_path_count": 0.0,
                "attempted_bridge_cell_count": 0.0,
                "trial_score": old_profile["score"],
                "trial_component_count": old_profile["component_count"],
                "trial_short_count": old_profile["short_count"],
                "trial_attachment": old_profile["attachment"],
                "trial_top3": old_profile["top3"],
                "p143_class_repair_needed": 1.0 if class_repair_needed else 0.0,
                "p143_class_profile_improved": 0.0,
                "p143_class_score_before": old_profile["class_linework_score"],
                "p143_class_score_after": old_profile["class_linework_score"],
                "p143_class_small_area_fraction_before": (
                    old_profile["class_small_area_fraction"]),
                "p143_class_small_area_fraction_after": (
                    old_profile["class_small_area_fraction"]),
                "p143_crest_small_area_fraction_before": (
                    old_profile["crest_small_area_fraction"]),
                "p143_crest_small_area_fraction_after": (
                    old_profile["crest_small_area_fraction"]),
                "p143_branch_small_area_fraction_before": (
                    old_profile["branch_small_area_fraction"]),
                "p143_branch_small_area_fraction_after": (
                    old_profile["branch_small_area_fraction"]),
                "p144_class_path_option_count": 0.0,
                "p144_class_path_selected_count": 0.0,
                "p144_crest_path_option_count": 0.0,
                "p144_branch_path_option_count": 0.0,
                "p144_class_attempted_path_count": 0.0,
                "p144_class_found_path_count": 0.0,
                "p144_crest_promoted_spine_cell_count": 0.0,
                "p144_branch_promoted_spine_cell_count": 0.0,
                "p144_class_promoted_spine_cell_count": 0.0,
                "p144_class_path_profile_rejected_count": 0.0,
                "p1147_pair_option_count": 0.0,
                "p1147_pair_selected_count": 0.0,
                "p1147_pair_balance_rejected_count": 0.0,
                "p1147_pair_profile_rejected_count": 0.0,
                "p1148_terminal_proxy_enabled": 0.0,
                "p1148_terminal_proxy_score_before": old_profile["score"],
                "p1148_terminal_proxy_score_after": old_profile["score"],
                "p1148_terminal_proxy_component_count_before": (
                    old_profile["component_count"]),
                "p1148_terminal_proxy_component_count_after": (
                    old_profile["component_count"]),
                "p1148_terminal_proxy_short_count_before": (
                    old_profile["short_count"]),
                "p1148_terminal_proxy_short_count_after": old_profile["short_count"],
            }
            empty_bridge = np.zeros(n, dtype=bool)
            if not old_spine.any():
                trial_info["reject_code"] = 1.0
                return (
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                    empty_bridge,
                    np.zeros(n, dtype=bool),
                    0,
                    False,
                    old_profile,
                    old_profile,
                    trial_info,
                )
            combined_already_good = old_profile["component_count"] <= 1.0 or (
                old_profile["score"] >= 0.995
                and old_profile["short_count"] <= 0.0
                and old_profile["attachment"] >= 1.0
            )
            if combined_already_good and not class_repair_needed:
                trial_info["reject_code"] = 2.0
                return (
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                    empty_bridge,
                    np.zeros(n, dtype=bool),
                    0,
                    False,
                    old_profile,
                    old_profile,
                    trial_info,
                )

            parent_core_bool = np.asarray(parent_core_mask, dtype=bool)
            parent_near_bool = np.asarray(parent_near_mask, dtype=bool)
            spine_near = self._dilate_mask(grid, old_spine, passes=3)
            peak_near = self._dilate_mask(grid, peak, passes=2)
            candidate = (
                cont_land
                & parent_near_bool
                & ~crest_bool
                & ~branch_bool
                & ~foreland_bool
                & (rel >= 120.0)
                & (rel <= 3400.0)
                & (
                    spine_near
                    | parent_core_bool
                    | (self._same_neighbor_count(grid, peak) >= 1)
                    | peak_near
                )
            )
            if not candidate.any() and not class_repair_needed:
                trial_info["reject_code"] = 3.0
                return (
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                    empty_bridge,
                    candidate,
                    0,
                    False,
                    old_profile,
                    old_profile,
                    trial_info,
                )

            support = peak | candidate
            bridge = np.zeros(n, dtype=bool)
            crest_class_bridge = np.zeros(n, dtype=bool)
            branch_class_bridge = np.zeros(n, dtype=bool)
            budget = max(
                float(max_fraction) * total_area,
                float(area[peak].min()) if peak.any() else 0.0,
            )
            used_area = 0.0
            path_count = 0
            rank = (
                score
                + 0.24 * np.clip(rel, 0.0, 4200.0)
                + 200.0 * old_spine.astype(np.float64)
                + 140.0 * parent_core_bool.astype(np.float64)
                + 90.0 * self._same_neighbor_count(grid, old_spine)
                + 45.0 * self._same_neighbor_count(grid, peak)
            )
            support_component_count = 0
            multi_spine_support_component_count = 0
            attempted_path_count = 0
            found_path_count = 0
            p1147_pair_balance_rejected_count = 0
            p1147_pair_profile_rejected_count = 0
            p144_class_attempted_path_count = 0
            p144_class_found_path_count = 0
            p144_crest_path_option_count = 0
            p144_branch_path_option_count = 0
            p144_class_path_selected_count = 0
            p144_class_path_profile_rejected_count = 0
            path_options: list[tuple[float, np.ndarray, int]] = []
            for support_comp in self._components(grid, support):
                support_component_count += 1
                comp_mask = np.zeros(n, dtype=bool)
                comp_mask[support_comp] = True
                spine_parts = self._components(grid, old_spine & comp_mask)
                if len(spine_parts) < 2:
                    continue
                multi_spine_support_component_count += 1
                reps = np.asarray([
                    int(comp[np.argmax(rank[comp])])
                    for comp in spine_parts
                ], dtype=np.int64)
                axis_values = component_axis_values(reps)
                ordered_indices = np.argsort(axis_values)
                max_steps = max(12, min(132, int(support_comp.size) + 8))
                pair_candidates: list[tuple[float, int, int]] = []
                seen_pairs: set[tuple[int, int]] = set()

                def add_pair(i: int, j: int, priority: float) -> None:
                    a_idx = int(i)
                    b_idx = int(j)
                    if a_idx == b_idx:
                        return
                    key = (
                        int(min(reps[a_idx], reps[b_idx])),
                        int(max(reps[a_idx], reps[b_idx])),
                    )
                    if key in seen_pairs:
                        return
                    seen_pairs.add(key)
                    pair_candidates.append((float(priority), a_idx, b_idx))

                for i, j in zip(ordered_indices[:-1], ordered_indices[1:]):
                    axis_gap = abs(float(axis_values[i]) - float(axis_values[j]))
                    add_pair(
                        int(i),
                        int(j),
                        axis_gap - 0.15,
                    )
                for i in range(reps.size):
                    for j in range(i + 1, reps.size):
                        axis_gap = abs(float(axis_values[i]) - float(axis_values[j]))
                        geo_gap = 1.0 - float(grid.xyz[reps[i]] @ grid.xyz[reps[j]])
                        add_pair(
                            i,
                            j,
                            axis_gap + 0.25 * geo_gap + 0.02 * float(j - i),
                        )
                pair_candidates.sort(key=lambda item: item[0])
                for _, i, j in pair_candidates[:24]:
                    attempted_path_count += 1
                    path = self._shortest_path_within_mask(
                        grid,
                        int(reps[i]),
                        int(reps[j]),
                        support & comp_mask,
                        max_steps=max_steps,
                    )
                    if path.size < 2 or path.size > max_steps:
                        continue
                    found_path_count += 1
                    cells = np.unique(path[candidate[path]])
                    if cells.size == 0:
                        continue
                    path_area = float(area[cells].sum())
                    if path_area > budget:
                        continue
                    path_options.append((float(path_area), cells, 0))
            if class_repair_needed:
                def add_class_path_options(
                    class_mask: np.ndarray,
                    class_spine: np.ndarray,
                    option_kind: int,
                ) -> tuple[int, int, int]:
                    class_bool = np.asarray(class_mask, dtype=bool)
                    spine_bool = np.asarray(class_spine, dtype=bool) & class_bool
                    option_count = 0
                    attempted = 0
                    found = 0
                    for class_comp in self._components(grid, class_bool):
                        comp_mask = np.zeros(n, dtype=bool)
                        comp_mask[class_comp] = True
                        spine_parts = self._components(
                            grid,
                            spine_bool & comp_mask,
                        )
                        if len(spine_parts) < 2:
                            continue
                        reps = np.asarray([
                            int(comp[np.argmax(rank[comp])])
                            for comp in spine_parts
                        ], dtype=np.int64)
                        axis_values = component_axis_values(reps)
                        ordered_indices = np.argsort(axis_values)
                        max_steps = max(12, min(132, int(class_comp.size) + 8))
                        pair_candidates: list[tuple[float, int, int]] = []
                        seen_pairs: set[tuple[int, int]] = set()

                        def add_class_pair(
                            i: int,
                            j: int,
                            priority: float,
                        ) -> None:
                            a_idx = int(i)
                            b_idx = int(j)
                            if a_idx == b_idx:
                                return
                            key = (
                                int(min(reps[a_idx], reps[b_idx])),
                                int(max(reps[a_idx], reps[b_idx])),
                            )
                            if key in seen_pairs:
                                return
                            seen_pairs.add(key)
                            pair_candidates.append((
                                float(priority),
                                a_idx,
                                b_idx,
                            ))

                        for i, j in zip(ordered_indices[:-1], ordered_indices[1:]):
                            axis_gap = abs(
                                float(axis_values[i]) - float(axis_values[j]))
                            add_class_pair(int(i), int(j), axis_gap - 0.20)
                        for i in range(reps.size):
                            for j in range(i + 1, reps.size):
                                axis_gap = abs(
                                    float(axis_values[i]) - float(axis_values[j]))
                                geo_gap = (
                                    1.0
                                    - float(grid.xyz[reps[i]] @ grid.xyz[reps[j]])
                                )
                                add_class_pair(
                                    i,
                                    j,
                                    axis_gap + 0.25 * geo_gap + 0.02 * float(j - i),
                                )
                        pair_candidates.sort(key=lambda item: item[0])
                        for _, i, j in pair_candidates[:24]:
                            attempted += 1
                            path = self._shortest_path_within_mask(
                                grid,
                                int(reps[i]),
                                int(reps[j]),
                                class_bool & comp_mask,
                                max_steps=max_steps,
                            )
                            if path.size < 2 or path.size > max_steps:
                                continue
                            found += 1
                            cells = np.unique(path[class_bool[path] & ~spine_bool[path]])
                            if cells.size == 0:
                                continue
                            path_area = float(area[cells].sum())
                            if path_area > budget:
                                continue
                            path_options.append((float(path_area), cells, option_kind))
                            option_count += 1
                    return option_count, attempted, found

                (
                    p144_crest_path_option_count,
                    crest_attempted,
                    crest_found,
                ) = add_class_path_options(crest_bool, old_crest_spine, 3)
                (
                    p144_branch_path_option_count,
                    branch_attempted,
                    branch_found,
                ) = add_class_path_options(branch_bool, old_branch_spine, 2)
                p144_class_attempted_path_count = crest_attempted + branch_attempted
                p144_class_found_path_count = crest_found + branch_found
            path_options.sort(
                key=lambda item: (
                    0 if item[2] in (2, 3) else 1,
                    float(area[item[1]].sum()),
                    -float(rank[item[1]].mean()) if item[1].size else 0.0,
                )
            )
            remaining_options = path_options.copy()
            current_profile = old_profile
            while remaining_options and used_area < budget:
                best_index = -1
                best_key: tuple[float, float, float, float, float] | None = None
                best_cells = np.zeros(0, dtype=np.int64)
                best_kind = 0
                best_profile = current_profile
                carried_options: list[tuple[float, np.ndarray, int]] = []
                for option_index, (
                    path_area_hint,
                    option_cells,
                    option_kind,
                ) in enumerate(
                    remaining_options
                ):
                    if option_kind == 3:
                        cells = option_cells[
                            ~crest_class_bridge[option_cells]
                            & ~old_crest_spine[option_cells]
                        ]
                    elif option_kind == 2:
                        cells = option_cells[
                            ~branch_class_bridge[option_cells]
                            & ~old_branch_spine[option_cells]
                        ]
                    else:
                        cells = option_cells[~bridge[option_cells]]
                    if cells.size == 0:
                        continue
                    path_area = float(area[cells].sum())
                    if path_area <= 0.0 or used_area + path_area > budget:
                        continue
                    trial_bridge = bridge.copy()
                    trial_crest_class_bridge = crest_class_bridge.copy()
                    trial_branch_class_bridge = branch_class_bridge.copy()
                    if option_kind == 3:
                        trial_crest_class_bridge[cells] = True
                    elif option_kind == 2:
                        trial_branch_class_bridge[cells] = True
                    else:
                        trial_bridge[cells] = True
                    trial_crest = crest_bool.copy()
                    trial_branch = (
                        (branch_bool | trial_bridge)
                        & cont_land
                        & ~trial_crest
                    )
                    trial_crest_spine = (
                        old_crest_spine | trial_crest_class_bridge
                    ) & trial_crest
                    trial_branch_spine = (
                        (
                            old_branch_spine
                            | trial_bridge
                            | trial_branch_class_bridge
                        )
                        & trial_branch
                        & ~trial_crest_spine
                    )
                    trial_peak = trial_crest | trial_branch
                    trial_profile = spine_linework_profile(
                        trial_crest_spine,
                        trial_branch_spine,
                        trial_peak,
                    )
                    spine_reduction = (
                        current_profile["component_count"]
                        - trial_profile["component_count"]
                    )
                    peak_reduction = (
                        current_profile["peak_component_count"]
                        - trial_profile["peak_component_count"]
                    )
                    if spine_reduction + 1.0e-9 < peak_reduction:
                        p1147_pair_balance_rejected_count += 1
                        continue
                    branch_area_ok = (
                        float(area[trial_branch].sum() / total_area) <= 0.043
                    )
                    overlap_valid = (
                        not np.any(trial_crest_spine & trial_branch_spine)
                        and np.all(trial_crest[trial_crest_spine])
                        and np.all(trial_branch[trial_branch_spine])
                    )
                    profile_ok = (
                        branch_area_ok
                        and overlap_valid
                        and (
                            trial_profile["score"] + 1.0e-9
                            >= current_profile["score"]
                        )
                        and (
                            trial_profile["class_linework_score"] + 1.0e-9
                            >= current_profile["class_linework_score"]
                        )
                        and (
                            trial_profile["class_small_area_fraction"]
                            <= current_profile["class_small_area_fraction"] + 1.0e-9
                        )
                        and (
                            trial_profile["short_count"]
                            <= current_profile["short_count"] + 1.0e-9
                        )
                        and (
                            trial_profile["short_fraction"]
                            <= current_profile["short_fraction"] + 1.0e-9
                        )
                        and (
                            trial_profile["attachment"] + 1.0e-9
                            >= current_profile["attachment"]
                        )
                        and (
                            trial_profile["top3"] + 1.0e-9
                            >= current_profile["top3"]
                        )
                        and (
                            trial_profile["component_count"]
                            <= current_profile["component_count"] + 1.0e-9
                        )
                    )
                    improves_profile = (
                        trial_profile["score"] > current_profile["score"] + 1.0e-9
                        or (
                            trial_profile["class_linework_score"]
                            > current_profile["class_linework_score"] + 0.010
                        )
                        or (
                            trial_profile["class_small_area_fraction"]
                            < current_profile["class_small_area_fraction"] - 0.010
                        )
                        or spine_reduction > 1.0e-9
                        or (
                            trial_profile["short_count"]
                            < current_profile["short_count"] - 1.0e-9
                        )
                        or (
                            trial_profile["attachment"]
                            > current_profile["attachment"] + 1.0e-9
                        )
                        or (
                            trial_profile["top3"]
                            > current_profile["top3"] + 1.0e-9
                        )
                    )
                    if not profile_ok or not improves_profile:
                        p1147_pair_profile_rejected_count += 1
                        if option_kind in (2, 3):
                            p144_class_path_profile_rejected_count += 1
                        continue
                    key = (
                        trial_profile["score"] - current_profile["score"],
                        trial_profile["class_linework_score"]
                        - current_profile["class_linework_score"],
                        spine_reduction,
                        trial_profile["top3"] - current_profile["top3"],
                        -path_area_hint,
                    )
                    carried_options.append((
                        path_area_hint,
                        option_cells,
                        option_kind,
                    ))
                    if best_key is None or key > best_key:
                        best_key = key
                        best_index = len(carried_options) - 1
                        best_cells = cells
                        best_kind = option_kind
                        best_profile = trial_profile
                if best_index < 0 or best_cells.size == 0:
                    break
                if best_kind == 3:
                    crest_class_bridge[best_cells] = True
                    p144_class_path_selected_count += 1
                elif best_kind == 2:
                    branch_class_bridge[best_cells] = True
                    p144_class_path_selected_count += 1
                else:
                    bridge[best_cells] = True
                used_area += float(area[best_cells].sum())
                path_count += 1
                current_profile = best_profile
                remaining_options = [
                    option
                    for idx, option in enumerate(carried_options)
                    if idx != best_index
                ]
            trial_info["support_component_count"] = float(support_component_count)
            trial_info["multi_spine_support_component_count"] = float(
                multi_spine_support_component_count)
            trial_info["attempted_path_count"] = float(attempted_path_count)
            trial_info["found_path_count"] = float(found_path_count)
            trial_info["bridge_path_count"] = float(path_count)
            trial_info["attempted_bridge_cell_count"] = float(
                np.count_nonzero(bridge | crest_class_bridge | branch_class_bridge))
            trial_info["p144_class_path_option_count"] = float(
                p144_crest_path_option_count + p144_branch_path_option_count)
            trial_info["p144_class_path_selected_count"] = float(
                p144_class_path_selected_count)
            trial_info["p144_crest_path_option_count"] = float(
                p144_crest_path_option_count)
            trial_info["p144_branch_path_option_count"] = float(
                p144_branch_path_option_count)
            trial_info["p144_class_attempted_path_count"] = float(
                p144_class_attempted_path_count)
            trial_info["p144_class_found_path_count"] = float(
                p144_class_found_path_count)
            trial_info["p144_crest_promoted_spine_cell_count"] = float(
                np.count_nonzero(crest_class_bridge))
            trial_info["p144_branch_promoted_spine_cell_count"] = float(
                np.count_nonzero(branch_class_bridge))
            trial_info["p144_class_promoted_spine_cell_count"] = float(
                np.count_nonzero(crest_class_bridge | branch_class_bridge))
            trial_info["p144_class_path_profile_rejected_count"] = float(
                p144_class_path_profile_rejected_count)
            trial_info["p1147_pair_option_count"] = float(len(path_options))
            trial_info["p1147_pair_selected_count"] = float(path_count)
            trial_info["p1147_pair_balance_rejected_count"] = float(
                p1147_pair_balance_rejected_count)
            trial_info["p1147_pair_profile_rejected_count"] = float(
                p1147_pair_profile_rejected_count)
            selected_bridge = bridge | crest_class_bridge | branch_class_bridge
            if not selected_bridge.any():
                if (
                    class_repair_needed
                    and p144_crest_path_option_count + p144_branch_path_option_count <= 0
                ):
                    trial_info["reject_code"] = 19.0
                elif multi_spine_support_component_count <= 0:
                    trial_info["reject_code"] = 4.0
                elif attempted_path_count <= 0:
                    trial_info["reject_code"] = 5.0
                elif found_path_count <= 0:
                    trial_info["reject_code"] = 6.0
                else:
                    trial_info["reject_code"] = 7.0
                return (
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    candidate,
                    0,
                    False,
                    old_profile,
                    old_profile,
                    trial_info,
                )

            new_crest = crest_bool.copy()
            new_branch = (branch_bool | bridge) & cont_land & ~new_crest
            new_crest_spine = (
                old_crest_spine | crest_class_bridge
            ) & new_crest
            new_branch_spine = (
                (old_branch_spine | bridge | branch_class_bridge)
                & new_branch
                & ~new_crest_spine
            )
            new_peak = new_crest | new_branch
            new_profile = spine_linework_profile(
                new_crest_spine,
                new_branch_spine,
                new_peak,
            )
            terminal_proxy_enabled = (
                world.g("terrain.enable_p1148_terminal_cleanup_proxy_guard", 1.0)
                > 0.0
            )
            terminal_proxy_ok = True
            if terminal_proxy_enabled:
                old_terminal_profile = terminal_cleanup_proxy_profile(
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                )
                new_terminal_profile = terminal_cleanup_proxy_profile(
                    new_crest,
                    new_branch,
                    new_crest_spine,
                    new_branch_spine,
                )
                trial_info["p1148_terminal_proxy_enabled"] = 1.0
                trial_info["p1148_terminal_proxy_score_before"] = (
                    old_terminal_profile["score"])
                trial_info["p1148_terminal_proxy_score_after"] = (
                    new_terminal_profile["score"])
                trial_info["p1148_terminal_proxy_component_count_before"] = (
                    old_terminal_profile["component_count"])
                trial_info["p1148_terminal_proxy_component_count_after"] = (
                    new_terminal_profile["component_count"])
                trial_info["p1148_terminal_proxy_short_count_before"] = (
                    old_terminal_profile["short_count"])
                trial_info["p1148_terminal_proxy_short_count_after"] = (
                    new_terminal_profile["short_count"])
                terminal_proxy_ok = (
                    new_terminal_profile["score"] + 1.0e-9
                    >= old_terminal_profile["score"]
                    and (
                        new_terminal_profile["short_count"]
                        <= old_terminal_profile["short_count"] + 1.0e-9
                    )
                    and (
                        new_terminal_profile["component_count"]
                        <= old_terminal_profile["component_count"] + 1.0e-9
                    )
                )
            trial_info["trial_score"] = new_profile["score"]
            trial_info["trial_component_count"] = new_profile["component_count"]
            trial_info["trial_short_count"] = new_profile["short_count"]
            trial_info["trial_attachment"] = new_profile["attachment"]
            trial_info["trial_top3"] = new_profile["top3"]
            class_profile_improved = (
                new_profile["class_linework_score"]
                > old_profile["class_linework_score"] + 0.010
                or (
                    new_profile["class_small_area_fraction"]
                    < old_profile["class_small_area_fraction"] - 0.010
                )
            )
            trial_info["p143_class_profile_improved"] = (
                1.0 if class_profile_improved else 0.0)
            trial_info["p143_class_score_after"] = (
                new_profile["class_linework_score"])
            trial_info["p143_class_small_area_fraction_after"] = (
                new_profile["class_small_area_fraction"])
            trial_info["p143_crest_small_area_fraction_after"] = (
                new_profile["crest_small_area_fraction"])
            trial_info["p143_branch_small_area_fraction_after"] = (
                new_profile["branch_small_area_fraction"])
            branch_area_ok = float(area[new_branch].sum() / total_area) <= 0.043
            overlap_valid = (
                not np.any(new_crest_spine & new_branch_spine)
                and np.all(new_crest[new_crest_spine])
                and np.all(new_branch[new_branch_spine])
            )
            score_ok = (
                new_profile["score"] + 1.0e-9
                >= max(old_profile["score"], 0.74)
            )
            short_ok = (
                new_profile["short_count"] <= old_profile["short_count"] + 1.0e-9
                and new_profile["short_fraction"] <= old_profile["short_fraction"] + 1.0e-9
            )
            attachment_ok = (
                new_profile["attachment"] + 1.0e-9 >= old_profile["attachment"])
            top3_ok = new_profile["top3"] + 1.0e-9 >= old_profile["top3"]
            component_ok = (
                new_profile["component_count"] <= old_profile["component_count"] + 1.0e-9
            )
            class_profile_ok = (
                new_profile["class_linework_score"] + 1.0e-9
                >= old_profile["class_linework_score"]
                and new_profile["class_small_area_fraction"]
                <= old_profile["class_small_area_fraction"] + 1.0e-9
            )
            improved = (
                new_profile["score"] > old_profile["score"] + 0.010
                or class_profile_improved
                or (
                    new_profile["component_count"]
                    < old_profile["component_count"] - 1.0e-9
                )
                or new_profile["short_count"] < old_profile["short_count"] - 1.0e-9
                or new_profile["top3"] > old_profile["top3"] + 0.010
            )
            accepted = (
                branch_area_ok
                and overlap_valid
                and score_ok
                and short_ok
                and attachment_ok
                and top3_ok
                and component_ok
                and class_profile_ok
                and terminal_proxy_ok
                and improved
            )
            if not accepted:
                if not branch_area_ok:
                    trial_info["reject_code"] = 8.0
                elif not overlap_valid:
                    trial_info["reject_code"] = 9.0
                elif not terminal_proxy_ok:
                    trial_info["reject_code"] = 17.0
                elif not score_ok:
                    trial_info["reject_code"] = 10.0
                elif not short_ok:
                    trial_info["reject_code"] = 11.0
                elif not attachment_ok:
                    trial_info["reject_code"] = 12.0
                elif not top3_ok:
                    trial_info["reject_code"] = 13.0
                elif not component_ok:
                    trial_info["reject_code"] = 14.0
                elif not class_profile_ok:
                    trial_info["reject_code"] = 18.0
                else:
                    trial_info["reject_code"] = 15.0
                return (
                    crest_bool,
                    branch_bool,
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    candidate,
                    0,
                    False,
                    old_profile,
                    new_profile,
                    trial_info,
                )
            trial_info["reject_code"] = 16.0
            return (
                new_crest,
                new_branch,
                new_crest_spine,
                new_branch_spine,
                selected_bridge,
                candidate,
                path_count,
                True,
                old_profile,
                new_profile,
                trial_info,
            )

        def consolidate_class_hierarchy_components(
            crest_mask: np.ndarray,
            branch_mask: np.ndarray,
            foreland_mask: np.ndarray,
            crest_spine_mask: np.ndarray,
            branch_spine_mask: np.ndarray,
            support_mask: np.ndarray,
            protected_mask: np.ndarray,
            max_fraction: float,
        ) -> tuple[
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            np.ndarray,
            bool,
            dict[str, float],
        ]:
            """Demote unsupported tiny crest/branch hierarchy islands."""
            crest_bool = np.asarray(crest_mask, dtype=bool) & cont_land
            branch_bool = (
                np.asarray(branch_mask, dtype=bool)
                & cont_land
                & ~crest_bool
            )
            foreland_bool = (
                np.asarray(foreland_mask, dtype=bool)
                & cont_land
                & ~crest_bool
                & ~branch_bool
            )
            old_crest_spine = np.asarray(crest_spine_mask, dtype=bool) & crest_bool
            old_branch_spine = (
                np.asarray(branch_spine_mask, dtype=bool)
                & branch_bool
                & ~old_crest_spine
            )
            old_profile = spine_linework_profile(
                old_crest_spine,
                old_branch_spine,
                crest_bool | branch_bool,
            )
            protected_bool = np.asarray(protected_mask, dtype=bool)
            if protected_bool.shape != (n,):
                protected_bool = np.zeros(n, dtype=bool)
            support_bool = np.asarray(support_mask, dtype=bool)
            if support_bool.shape != (n,):
                support_bool = np.zeros(n, dtype=bool)
            else:
                support_bool = support_bool & cont_land
            budget = max(float(max_fraction) * total_area, 0.0)
            if budget <= 0.0:
                return (
                    crest_bool,
                    branch_bool,
                    foreland_bool,
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    False,
                    {
                        "class_score_before": old_profile["class_linework_score"],
                        "class_score_after": old_profile["class_linework_score"],
                        "class_small_before": old_profile["class_small_area_fraction"],
                        "class_small_after": old_profile["class_small_area_fraction"],
                        "crest_small_before": old_profile["crest_small_area_fraction"],
                        "crest_small_after": old_profile["crest_small_area_fraction"],
                        "branch_small_before": old_profile["branch_small_area_fraction"],
                        "branch_small_after": old_profile["branch_small_area_fraction"],
                    },
                )
            class_component_count = (
                old_profile["crest_component_count"]
                + old_profile["branch_component_count"]
            )
            class_repair_needed = (
                old_profile["score"] >= 0.75
                and old_profile["class_linework_score"]
                <= old_profile["score"] - 0.22
                and old_profile["class_small_area_fraction"] >= 0.55
                and class_component_count >= 12.0
            )
            if not class_repair_needed:
                return (
                    crest_bool,
                    branch_bool,
                    foreland_bool,
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    False,
                    {
                        "class_score_before": old_profile["class_linework_score"],
                        "class_score_after": old_profile["class_linework_score"],
                        "class_small_before": old_profile["class_small_area_fraction"],
                        "class_small_after": old_profile["class_small_area_fraction"],
                        "crest_small_before": old_profile["crest_small_area_fraction"],
                        "crest_small_after": old_profile["crest_small_area_fraction"],
                        "branch_small_before": old_profile["branch_small_area_fraction"],
                        "branch_small_after": old_profile["branch_small_area_fraction"],
                    },
                )

            candidates: list[tuple[float, int, np.ndarray]] = []

            def collect_candidates(
                class_mask: np.ndarray,
                class_spine: np.ndarray,
                class_code: int,
            ) -> None:
                class_spine_bool = np.asarray(class_spine, dtype=bool)
                class_neighbor_count = self._same_neighbor_count(
                    grid,
                    class_mask,
                )
                for comp in self._components(grid, class_mask):
                    comp = np.asarray(comp, dtype=np.int64)
                    if comp.size == 0 or comp.size > 12:
                        continue
                    spine_count = int(np.count_nonzero(class_spine_bool[comp]))
                    is_tiny = comp.size <= 8
                    is_small_underfilled = comp.size <= 12 and spine_count <= 8
                    if not (is_tiny or is_small_underfilled):
                        continue
                    max_rel = float(np.max(rel[comp])) if comp.size else 0.0
                    protected_hits = int(np.count_nonzero(protected_bool[comp]))
                    if max_rel >= 3300.0:
                        continue
                    if protected_hits > 0 and max_rel >= 2500.0 and comp.size >= 6:
                        continue
                    neighbor_support = float(np.max(class_neighbor_count[comp]))
                    priority = (
                        float(comp.size)
                        + 0.002 * max_rel
                        + 0.50 * float(protected_hits)
                        + 0.15 * neighbor_support
                    )
                    candidates.append((priority, int(class_code), comp))

            collect_candidates(crest_bool, old_crest_spine, 3)
            collect_candidates(branch_bool, old_branch_spine, 2)
            candidates.sort(key=lambda item: item[0])

            removed_crest = np.zeros(n, dtype=bool)
            removed_branch = np.zeros(n, dtype=bool)
            added_crest = np.zeros(n, dtype=bool)
            added_branch = np.zeros(n, dtype=bool)
            used_area = 0.0
            bridge_path_count = 0
            current_profile = old_profile

            def evaluate_change(
                trial_added_crest: np.ndarray,
                trial_added_branch: np.ndarray,
                trial_removed_crest: np.ndarray,
                trial_removed_branch: np.ndarray,
            ) -> tuple[
                np.ndarray,
                np.ndarray,
                np.ndarray,
                np.ndarray,
                np.ndarray,
                dict[str, float],
            ]:
                trial_crest = (crest_bool | trial_added_crest) & ~trial_removed_crest
                trial_branch = (
                    (branch_bool | trial_added_branch)
                    & ~trial_removed_branch
                    & ~trial_crest
                )
                trial_foreland = foreland_bool & ~trial_crest & ~trial_branch
                trial_crest_spine = (old_crest_spine | trial_added_crest) & trial_crest
                trial_branch_spine = (
                    (old_branch_spine | trial_added_branch)
                    & trial_branch
                    & ~trial_crest_spine
                )
                trial_profile = spine_linework_profile(
                    trial_crest_spine,
                    trial_branch_spine,
                    trial_crest | trial_branch,
                )
                return (
                    trial_crest,
                    trial_branch,
                    trial_foreland,
                    trial_crest_spine,
                    trial_branch_spine,
                    trial_profile,
                )

            def profile_accepts(
                trial_profile: dict[str, float],
                baseline_profile: dict[str, float],
            ) -> bool:
                class_small_improved = (
                    trial_profile["class_small_area_fraction"]
                    < baseline_profile["class_small_area_fraction"] - 1.0e-9
                )
                class_score_improved = (
                    trial_profile["class_linework_score"]
                    > baseline_profile["class_linework_score"] + 0.005
                )
                class_score_safe = (
                    trial_profile["class_linework_score"] + 0.005
                    >= baseline_profile["class_linework_score"]
                    and trial_profile["class_linework_score"] + 0.010
                    >= old_profile["class_linework_score"]
                )
                profile_safe = (
                    trial_profile["score"] + 1.0e-9 >= old_profile["score"] * 0.96
                    and trial_profile["attachment"] + 1.0e-9
                    >= old_profile["attachment"]
                    and class_score_safe
                    and trial_profile["class_small_area_fraction"]
                    <= baseline_profile["class_small_area_fraction"] + 1.0e-9
                )
                return bool(
                    profile_safe and (class_small_improved or class_score_improved))

            def try_bridge_class_components(
                class_mask: np.ndarray,
                class_spine: np.ndarray,
                class_code: int,
            ) -> None:
                nonlocal added_crest, added_branch, used_area
                nonlocal current_profile, bridge_path_count
                class_bool = np.asarray(class_mask, dtype=bool)
                spine_bool = np.asarray(class_spine, dtype=bool) & class_bool
                spine_parts = self._components(grid, spine_bool)
                if len(spine_parts) < 2:
                    return
                reps = np.asarray([
                    int(comp[np.argmax(score[comp] + 0.20 * rel[comp])])
                    for comp in spine_parts
                ], dtype=np.int64)
                pair_candidates: list[tuple[float, int, int]] = []
                for i in range(reps.size):
                    for j in range(i + 1, reps.size):
                        dot = float(grid.xyz[reps[i]] @ grid.xyz[reps[j]])
                        pair_candidates.append((1.0 - dot, i, j))
                pair_candidates.sort(key=lambda item: item[0])
                other_class = branch_bool if int(class_code) == 3 else crest_bool
                allowed = (
                    cont_land
                    & (class_bool | foreland_bool | support_bool)
                    & ~other_class
                    & (rel >= 0.0)
                    & (rel < 3300.0)
                )
                bridge_rank = (
                    score
                    + 0.12 * np.clip(rel, 0.0, 3300.0)
                    + 160.0 * foreland_bool.astype(np.float64)
                    + 90.0 * class_bool.astype(np.float64)
                )
                for _, i, j in pair_candidates[:40]:
                    if used_area >= budget:
                        break
                    path = self._ranked_shortest_path_within_mask(
                        grid,
                        int(reps[i]),
                        int(reps[j]),
                        allowed,
                        bridge_rank,
                        max_steps=14,
                    )
                    if path.size < 2 or path.size > 14:
                        continue
                    cells = np.unique(
                        path[
                            (foreland_bool[path] | support_bool[path])
                            & ~class_bool[path]
                            & ~other_class[path]
                        ]
                    )
                    if cells.size == 0:
                        continue
                    cells = cells[
                        ~added_crest[cells]
                        & ~added_branch[cells]
                        & ~removed_crest[cells]
                        & ~removed_branch[cells]
                    ]
                    if cells.size == 0:
                        continue
                    path_area = float(area[cells].sum())
                    if path_area <= 0.0 or used_area + path_area > budget:
                        continue
                    trial_added_crest = added_crest.copy()
                    trial_added_branch = added_branch.copy()
                    if int(class_code) == 3:
                        trial_added_crest[cells] = True
                    else:
                        trial_added_branch[cells] = True
                    (
                        _trial_crest,
                        _trial_branch,
                        _trial_foreland,
                        _trial_crest_spine,
                        _trial_branch_spine,
                        trial_profile,
                    ) = evaluate_change(
                        trial_added_crest,
                        trial_added_branch,
                        removed_crest,
                        removed_branch,
                    )
                    if not profile_accepts(trial_profile, current_profile):
                        continue
                    added_crest = trial_added_crest
                    added_branch = trial_added_branch
                    current_profile = trial_profile
                    used_area += path_area
                    bridge_path_count += 1

            try_bridge_class_components(crest_bool, old_crest_spine, 3)
            try_bridge_class_components(branch_bool, old_branch_spine, 2)

            added = added_crest | added_branch
            if added.any():
                (
                    new_crest,
                    new_branch,
                    new_foreland,
                    new_crest_spine,
                    new_branch_spine,
                    new_profile,
                ) = evaluate_change(
                    added_crest,
                    added_branch,
                    removed_crest,
                    removed_branch,
                )
                return (
                    new_crest,
                    new_branch,
                    new_foreland,
                    new_crest_spine,
                    new_branch_spine,
                    added_crest,
                    added_branch,
                    removed_crest,
                    removed_branch,
                    True,
                    {
                        "class_score_before": old_profile["class_linework_score"],
                        "class_score_after": new_profile["class_linework_score"],
                        "class_small_before": old_profile["class_small_area_fraction"],
                        "class_small_after": new_profile["class_small_area_fraction"],
                        "crest_small_before": old_profile["crest_small_area_fraction"],
                        "crest_small_after": new_profile["crest_small_area_fraction"],
                        "branch_small_before": old_profile["branch_small_area_fraction"],
                        "branch_small_after": new_profile["branch_small_area_fraction"],
                        "added_crest_cell_count": float(np.count_nonzero(added_crest)),
                        "added_branch_cell_count": float(np.count_nonzero(added_branch)),
                        "added_crest_area_fraction": float(
                            area[added_crest].sum() / total_area),
                        "added_branch_area_fraction": float(
                            area[added_branch].sum() / total_area),
                        "bridge_path_count": float(bridge_path_count),
                    },
                )

            for _, class_code, comp in candidates:
                comp_area = float(area[comp].sum())
                if comp_area <= 0.0 or used_area + comp_area > budget:
                    continue
                trial_removed_crest = removed_crest.copy()
                trial_removed_branch = removed_branch.copy()
                if class_code == 3:
                    trial_removed_crest[comp] = True
                else:
                    trial_removed_branch[comp] = True
                (
                    _trial_crest,
                    _trial_branch,
                    _trial_foreland,
                    _trial_crest_spine,
                    _trial_branch_spine,
                    trial_profile,
                ) = evaluate_change(
                    added_crest,
                    added_branch,
                    trial_removed_crest,
                    trial_removed_branch,
                )
                if not profile_accepts(trial_profile, current_profile):
                    continue
                removed_crest = trial_removed_crest
                removed_branch = trial_removed_branch
                current_profile = trial_profile
                used_area += comp_area

            removed = removed_crest | removed_branch
            if not removed.any():
                return (
                    crest_bool,
                    branch_bool,
                    foreland_bool,
                    old_crest_spine,
                    old_branch_spine,
                    added_crest,
                    added_branch,
                    removed_crest,
                    removed_branch,
                    False,
                    {
                        "class_score_before": old_profile["class_linework_score"],
                        "class_score_after": old_profile["class_linework_score"],
                        "class_small_before": old_profile["class_small_area_fraction"],
                        "class_small_after": old_profile["class_small_area_fraction"],
                        "crest_small_before": old_profile["crest_small_area_fraction"],
                        "crest_small_after": old_profile["crest_small_area_fraction"],
                        "branch_small_before": old_profile["branch_small_area_fraction"],
                        "branch_small_after": old_profile["branch_small_area_fraction"],
                    },
                )

            (
                new_crest,
                new_branch,
                new_foreland,
                new_crest_spine,
                new_branch_spine,
                new_profile,
            ) = evaluate_change(
                added_crest,
                added_branch,
                removed_crest,
                removed_branch,
            )
            profile_improved = (
                new_profile["class_linework_score"]
                > old_profile["class_linework_score"] + 1.0e-9
                or (
                    new_profile["class_small_area_fraction"]
                    < old_profile["class_small_area_fraction"] - 1.0e-9
                )
            )
            profile_safe = (
                new_profile["score"] + 1.0e-9 >= old_profile["score"] * 0.96
                and new_profile["attachment"] + 1.0e-9 >= old_profile["attachment"]
                and new_profile["class_linework_score"] + 0.010
                >= old_profile["class_linework_score"]
                and new_profile["class_small_area_fraction"]
                <= old_profile["class_small_area_fraction"] + 1.0e-9
            )
            accepted = bool(profile_improved and profile_safe)
            if not accepted:
                return (
                    crest_bool,
                    branch_bool,
                    foreland_bool,
                    old_crest_spine,
                    old_branch_spine,
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    np.zeros(n, dtype=bool),
                    False,
                    {
                        "class_score_before": old_profile["class_linework_score"],
                        "class_score_after": new_profile["class_linework_score"],
                        "class_small_before": old_profile["class_small_area_fraction"],
                        "class_small_after": new_profile["class_small_area_fraction"],
                        "crest_small_before": old_profile["crest_small_area_fraction"],
                        "crest_small_after": new_profile["crest_small_area_fraction"],
                        "branch_small_before": old_profile["branch_small_area_fraction"],
                        "branch_small_after": new_profile["branch_small_area_fraction"],
                    },
                )
            return (
                new_crest,
                new_branch,
                new_foreland,
                new_crest_spine,
                new_branch_spine,
                added_crest,
                added_branch,
                removed_crest,
                removed_branch,
                True,
                {
                    "class_score_before": old_profile["class_linework_score"],
                    "class_score_after": new_profile["class_linework_score"],
                    "class_small_before": old_profile["class_small_area_fraction"],
                    "class_small_after": new_profile["class_small_area_fraction"],
                    "crest_small_before": old_profile["crest_small_area_fraction"],
                    "crest_small_after": new_profile["crest_small_area_fraction"],
                    "branch_small_before": old_profile["branch_small_area_fraction"],
                    "branch_small_after": new_profile["branch_small_area_fraction"],
                },
            )

        hierarchy = np.zeros(n, dtype=np.float64)
        hierarchy_spine = np.zeros(n, dtype=np.float64)
        shoulder_halo = np.zeros(n, dtype=np.float64)
